import React, { useState, useMemo } from 'react';
import { UserRole, Tenant, House, PaymentRecord, Expense, HouseStatus } from './types';
import { INITIAL_TENANTS, INITIAL_HOUSES, INITIAL_PAYMENTS } from './constants';
import { Layout } from './components/Layout';
import { CaretakerDashboard } from './components/CaretakerDashboard';
import { LandlordDashboard } from './components/LandlordDashboard';
import { TenantDashboard } from './components/TenantDashboard';
import { Users, ShieldCheck, Key, ArrowRight } from 'lucide-react';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [activeView, setActiveView] = useState<string>('dashboard');
  const [tenants, setTenants] = useState<Tenant[]>(INITIAL_TENANTS);
  const [houses, setHouses] = useState<House[]>(INITIAL_HOUSES);
  const [payments, setPayments] = useState<PaymentRecord[]>(INITIAL_PAYMENTS);
  const [expenses, setExpenses] = useState<Expense[]>([]);

  const handleAddTenant = (newTenant: Tenant) => {
    setTenants(prev => [...prev, newTenant]);
    setHouses(prev => prev.map(h => h.houseNumber === newTenant.houseNumber ? { ...h, status: HouseStatus.RENTED } : h));
  };

  const handleUpdateTenant = (updatedTenant: Tenant) => {
    setTenants(prev => prev.map(t => t.id === updatedTenant.id ? updatedTenant : t));
  };

  const handleUpdateBills = (tenantId: string, currentReading: number) => {
    setTenants(prev => prev.map(t => {
      if (t.id === tenantId) {
        // Calculate units used: current - previous
        const unitsUsed = Math.max(0, currentReading - t.bills.prevWaterReading);
        // Cost is 150 per unit
        const waterCost = unitsUsed * 150;
        const newTotal = t.bills.rent + waterCost + t.bills.garbage;

        return { 
          ...t, 
          bills: { 
            ...t.bills, 
            water: waterCost, 
            currWaterReading: currentReading,
            total: newTotal, 
            status: 'UNPAID' 
          } 
        };
      }
      return t;
    }));
  };

  const handlePayment = (payment: PaymentRecord) => {
    setPayments(prev => [payment, ...prev]);

    // Find the tenant to get their house number
    const tenant = tenants.find(t => t.id === payment.tenantId);

    // Update House Earnings if payment is Rent or Total (which includes rent)
    if (tenant && (payment.type === 'RENT' || payment.type === 'TOTAL')) {
      setHouses(prev => prev.map(h => {
        if (h.houseNumber === tenant.houseNumber) {
          // If it's a TOTAL payment, we estimate the rent portion or just add the amount 
          // to simplify for this management app logic
          return { ...h, totalEarnings: h.totalEarnings + payment.amount };
        }
        return h;
      }));
    }

    setTenants(prev => prev.map(t => {
      if (t.id === payment.tenantId) {
        const bills = { ...t.bills };
        if (payment.type === 'RENT') bills.rent = Math.max(0, bills.rent - payment.amount);
        else if (payment.type === 'WATER') bills.water = Math.max(0, bills.water - payment.amount);
        else if (payment.type === 'GARBAGE') bills.garbage = Math.max(0, bills.garbage - payment.amount);
        else {
          let rem = payment.amount;
          const waterPay = Math.min(rem, bills.water);
          bills.water -= waterPay;
          rem -= waterPay;
          const garbagePay = Math.min(rem, bills.garbage);
          bills.garbage -= garbagePay;
          rem -= garbagePay;
          bills.rent = Math.max(0, bills.rent - rem);
        }
        bills.total = bills.rent + bills.water + bills.garbage;
        bills.status = bills.total <= 0 ? 'PAID' : 'PARTIAL';
        return { ...t, bills };
      }
      return t;
    }));
  };

  const handleHouseUpdate = (houseId: string, status: HouseStatus) => {
    setHouses(prev => prev.map(h => h.id === houseId ? { ...h, status } : h));
  };

  const handleAddExpense = (expense: Expense) => {
    setExpenses(prev => [expense, ...prev]);
  };

  const handleSetRole = (newRole: UserRole) => {
    setRole(newRole);
    if (newRole === UserRole.TENANT) {
      setActiveView('profile');
    } else {
      setActiveView('dashboard');
    }
  };

  const renderContent = () => {
    if (role === UserRole.CARETAKER) {
      return (
        <CaretakerDashboard 
          tenants={tenants} 
          houses={houses}
          payments={payments}
          activeTab={activeView === 'dashboard' ? 'houses' : activeView as any}
          onAddTenant={handleAddTenant}
          onUpdateTenant={handleUpdateTenant}
          onUpdateBills={handleUpdateBills}
          onUpdateHouse={handleHouseUpdate}
          onLogPayment={handlePayment}
        />
      );
    }
    if (role === UserRole.LANDLORD) {
      return (
        <LandlordDashboard 
          tenants={tenants} 
          houses={houses}
          payments={payments}
          expenses={expenses}
          view={activeView}
          onAddExpense={handleAddExpense}
        />
      );
    }
    if (role === UserRole.TENANT) {
      // Sort payments by date descending for history
      const tenantPayments = payments
        .filter(p => p.tenantId === tenants[0].id)
        .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

      return (
        <TenantDashboard 
          tenant={tenants[0]} 
          payments={tenantPayments}
          onPay={handlePayment}
          initialTab={activeView === 'payments' ? 'payments' : 'profile'}
        />
      );
    }
    return null;
  };

  if (!role) {
    return (
      <div className="min-h-screen bg-neutral-900 flex flex-col items-center justify-center p-6 text-white overflow-hidden relative">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_50%,rgba(31,106,225,0.1),transparent)] pointer-events-none" />
        <div className="mb-12 text-center animate-fadeIn relative z-10">
          <h1 className="text-7xl font-royal mb-4 text-royal-500 drop-shadow-2xl">ROYAL FLATS</h1>
          <p className="text-neutral-400 uppercase tracking-[0.6em] text-[10px] font-black">Management Intelligence System</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 w-full max-w-6xl animate-slideUp relative z-10">
          <RoleCard title="Resident" icon={<Key className="w-10 h-10"/>} description="Pay rent via M-Pesa, track utility consumption, and request support." onClick={() => handleSetRole(UserRole.TENANT)} />
          <RoleCard title="Caretaker" icon={<ShieldCheck className="w-10 h-10"/>} description="Manage unit occupancy, update meters, and notify tenants of arrears." onClick={() => handleSetRole(UserRole.CARETAKER)} highlight />
          <RoleCard title="Owner" icon={<Users className="w-10 h-10"/>} description="Portfolio analytics, financial reports, and expense tracking." onClick={() => handleSetRole(UserRole.LANDLORD)} />
        </div>
      </div>
    );
  }

  return (
    <Layout 
      role={role} 
      onLogout={() => { setRole(null); setActiveView('dashboard'); }} 
      activeView={activeView} 
      onViewChange={setActiveView}
    >
      {renderContent()}
    </Layout>
  );
};

const RoleCard: React.FC<{ title: string, icon: React.ReactNode, description: string, onClick: () => void, highlight?: boolean }> = ({ title, icon, description, onClick, highlight }) => (
  <button 
    onClick={onClick} 
    className={`p-10 rounded-[3rem] border transition-all duration-500 text-left group relative overflow-hidden h-full flex flex-col ${highlight ? 'border-royal-500/30 bg-royal-500/5 hover:bg-royal-500/10 hover:border-royal-500 shadow-2xl shadow-royal-900/20' : 'border-neutral-800 bg-neutral-800/30 hover:bg-neutral-800 hover:border-neutral-600 shadow-xl'}`}
  >
    <div className={`mb-8 p-5 rounded-2xl inline-block ${highlight ? 'bg-royal-500/20 text-royal-500' : 'bg-neutral-700 text-neutral-400'} group-hover:scale-110 transition-transform duration-500`}>
      {icon}
    </div>
    <h3 className="text-3xl font-royal mb-4 text-white font-bold">{title} Portal</h3>
    <p className="text-neutral-400 text-sm leading-relaxed mb-8 flex-1 font-medium">{description}</p>
    <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-all duration-300 text-royal-500 transform translate-y-4 group-hover:translate-y-0">
      Access Intelligence System <ArrowRight size={14}/>
    </div>
  </button>
);

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Tenant, House, HouseStatus, PaymentRecord } from '../types';
import { 
  UserPlus, Droplets, Send, Wrench, RefreshCw, X, User, Phone, Mail, 
  Hash, Home, CheckCircle2, CircleDashed, Hammer, Users, AlertTriangle, Clock, 
  History, DollarSign, Activity, Eye, Search, MapPin, ArrowRight, Save, Smartphone,
  Receipt, Calendar, ChevronRight, Filter, RotateCcw, Check, ShieldCheck, CreditCard,
  FileText, TrendingUp, MoreHorizontal, BellRing, UserCheck, Wallet, Edit3, Plus,
  ChevronDown
} from 'lucide-react';
import { generateTenantNotification, analyzeTenantFinancials } from '../services/geminiService';

interface Props {
  tenants: Tenant[];
  houses: House[];
  payments: PaymentRecord[];
  onAddTenant: (t: Tenant) => void;
  onUpdateTenant: (t: Tenant) => void;
  onUpdateBills: (id: string, currentReading: number) => void;
  onUpdateHouse: (id: string, status: HouseStatus) => void;
  onLogPayment?: (payment: PaymentRecord) => void;
  activeTab?: string;
}

export const CaretakerDashboard: React.FC<Props> = ({ 
  tenants, houses, payments, onAddTenant, onUpdateTenant, onUpdateBills, onUpdateHouse, onLogPayment,
  activeTab: propTab 
}) => {
  const [activeTab, setActiveTab] = useState<'houses' | 'tenants' | 'billing'>('houses');
  const [showAddModal, setShowAddModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showLogPaymentModal, setShowLogPaymentModal] = useState(false);
  const [selectedHouse, setSelectedHouse] = useState<House | null>(null);
  const [selectedTenant, setSelectedTenant] = useState<Tenant | null>(null);
  const [tenantToEdit, setTenantToEdit] = useState<Tenant | null>(null);
  const [loadingAI, setLoadingAI] = useState<string | null>(null);
  const [updatedTenantId, setUpdatedTenantId] = useState<string | null>(null);

  const [pendingReadings, setPendingReadings] = useState<Record<string, number>>({});

  const [billFilterType, setBillFilterType] = useState<string>('ALL');
  const [billFilterMethod, setBillFilterMethod] = useState<string>('ALL');
  const [billStartDate, setBillStartDate] = useState<string>('');
  const [billEndDate, setBillEndDate] = useState<string>('');

  useEffect(() => {
    if (propTab) {
      if (propTab === 'houses' || propTab === 'properties') setActiveTab('houses');
      else if (propTab === 'tenants') setActiveTab('tenants');
      else if (propTab === 'billing' || propTab === 'payments') setActiveTab('billing');
    }
  }, [propTab]);

  const [newTenant, setNewTenant] = useState({
    name: '', email: '', houseNumber: '', idNumber: '', phoneNumber: '', nextOfKin: '', rent: 0
  });

  const filteredCollections = useMemo(() => {
    return payments.filter(p => {
      const matchesType = billFilterType === 'ALL' || p.type === billFilterType;
      const matchesMethod = billFilterMethod === 'ALL' || p.method === billFilterMethod;
      const paymentDate = new Date(p.date).getTime();
      const start = billStartDate ? new Date(billStartDate).getTime() : 0;
      const end = billEndDate ? new Date(billEndDate).getTime() : Infinity;
      const matchesDate = paymentDate >= start && paymentDate <= (end + 86400000);
      return matchesType && matchesMethod && matchesDate;
    });
  }, [payments, billFilterType, billFilterMethod, billStartDate, billEndDate]);

  const handleSendReminder = async (tenant: Tenant) => {
    setLoadingAI(tenant.id);
    try {
      const message = await generateTenantNotification(tenant.name, tenant.bills.total);
      alert(`AI Reminder for ${tenant.name}:\n\n"${message}"\n\nNotification sent to ${tenant.phoneNumber}`);
    } catch (err) { console.error(err); }
    finally { setLoadingAI(null); }
  };

  const handleRegisterTenant = (e: React.FormEvent) => {
    e.preventDefault();
    const tenant: Tenant = {
      id: `t-${Date.now()}`,
      name: newTenant.name,
      email: newTenant.email,
      houseNumber: newTenant.houseNumber,
      idNumber: newTenant.idNumber,
      phoneNumber: newTenant.phoneNumber,
      nextOfKin: newTenant.nextOfKin,
      joinDate: new Date().toISOString().split('T')[0],
      bills: { 
        rent: newTenant.rent, 
        water: 0, 
        prevWaterReading: 0,
        currWaterReading: 0,
        garbage: 500, 
        total: newTenant.rent + 500, 
        status: 'UNPAID' 
      }
    };
    onAddTenant(tenant);
    setShowAddModal(false);
    setNewTenant({ name: '', email: '', houseNumber: '', idNumber: '', phoneNumber: '', nextOfKin: '', rent: 0 });
  };

  const handleApplyUpdate = (tenantId: string) => {
    const reading = pendingReadings[tenantId];
    if (reading === undefined) return;
    onUpdateBills(tenantId, reading);
    setUpdatedTenantId(tenantId);
    setPendingReadings(prev => {
      const next = { ...prev };
      delete next[tenantId];
      return next;
    });
    setTimeout(() => setUpdatedTenantId(null), 2000);
  };

  const resetBillFilters = () => {
    setBillFilterType('ALL');
    setBillFilterMethod('ALL');
    setBillStartDate('');
    setBillEndDate('');
  };

  const handleEditClick = (tenant: Tenant) => {
    setTenantToEdit(tenant);
    setShowEditModal(true);
  };

  const handleManualPayment = (payment: PaymentRecord) => {
    if (onLogPayment) {
      onLogPayment(payment);
      setShowLogPaymentModal(false);
    }
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      {showAddModal && <AddTenantModal houses={houses} newTenant={newTenant} setNewTenant={setNewTenant} onClose={() => setShowAddModal(false)} onSubmit={handleRegisterTenant} />}
      {showLogPaymentModal && <LogPaymentModal tenants={tenants} onClose={() => setShowLogPaymentModal(false)} onSubmit={handleManualPayment} />}
