        <EditTenantModal 
          tenant={tenantToEdit} 
          onClose={() => { setShowEditModal(false); setTenantToEdit(null); }} 
          onSubmit={(updated) => { 
            onUpdateTenant(updated); 
            setShowEditModal(false); 
            setTenantToEdit(null);
            // Also refresh selected tenant if open
            if (selectedTenant && selectedTenant.id === updated.id) {
               setSelectedTenant(updated);
            }
          }} 
        />
      )}
      {selectedHouse && (
        <HouseDetailModal 
          house={selectedHouse} 
          onClose={() => setSelectedHouse(null)} 
          onUpdateStatus={(status) => {
            onUpdateHouse(selectedHouse.id, status);
            // Update local selected house state to reflect change immediately
            setSelectedHouse({...selectedHouse, status});
