            <button className="w-full mt-10 bg-royal-500 text-white py-5 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-royal-600 shadow-xl shadow-royal-500/20 active:scale-95 transition-all">Log Maintenance Event</button>
          </div>
        </div>
      )}
    </div>
  );
};

