                onChange={(e) => setFormData({...formData, amount: e.target.value})} 
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-neutral-400 uppercase tracking-widest flex items-center gap-2"><Receipt size={14}/> Payment For</label>
              <div className="relative">
                <select 
                  required 
                  className="w-full bg-neutral-50 border-2 border-neutral-100 p-4 rounded-2xl focus:border-royal-500 outline-none transition-all text-sm font-bold text-neutral-700 appearance-none" 
                  value={formData.type} 
                  onChange={(e) => setFormData({...formData, type: e.target.value as any})}
                >
