                <p className="text-[10px] font-black text-neutral-400 uppercase tracking-widest">Recent Maintenance</p>
                <div className="space-y-2">
                  {house.repairs.length > 0 ? (
                    house.repairs.map(r => (
                      <div key={r.id} className="flex justify-between items-center p-4 bg-neutral-50 rounded-xl border border-neutral-100">
                        <div>
                          <p className="text-sm font-bold text-neutral-800">{r.description}</p>
                          <p className="text-[10px] text-neutral-400 font-medium">{r.date}</p>
                        </div>
                        <p className="text-sm font-black text-neutral-900">KES {r.cost.toLocaleString()}</p>
                      </div>
                    ))
                  ) : (
                    <p className="text-xs text-neutral-400 italic">No maintenance records for this unit.</p>
                  )}
                </div>
              </div>
            </>
          ) : (
            <div className="animate-fadeIn space-y-8">
              <div className="bg-red-50 p-6 rounded-2xl border border-red-100 flex items-center gap-3">
                <Wrench className="text-red-500" size={24} />
                <div>
                  <h4 className="font-bold text-red-900">Required: Log Maintenance Event</h4>
                  <p className="text-xs text-red-600">Unit {house.houseNumber} will be set to 'Under Repair'. Please describe the issue.</p>
                </div>
              </div>

              <form onSubmit={handleRepairSubmit} className="space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-neutral-400 uppercase tracking-widest">Repair Description</label>
                  <textarea 
                    required 
                    className="w-full bg-neutral-50 border-2 border-neutral-100 p-4 rounded-2xl focus:border-red-500 outline-none transition-all text-sm font-medium text-neutral-700 h-32" 
                    placeholder="Describe the damages or maintenance required..."
                    value={repairData.description}
                    onChange={e => setRepairData({...repairData, description: e.target.value})}
                  />
                </div>
                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-neutral-400 uppercase tracking-widest">Estimated Cost (KES)</label>
                    <input 
                      type="number" 
                      required 
                      className="w-full bg-neutral-50 border-2 border-neutral-100 p-4 rounded-2xl focus:border-red-500 outline-none transition-all text-sm font-bold text-neutral-700" 
                      placeholder="0.00"
                      value={repairData.cost}
                      onChange={e => setRepairData({...repairData, cost: e.target.value})}
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-neutral-400 uppercase tracking-widest">Category</label>
                    <select 
                      className="w-full bg-neutral-50 border-2 border-neutral-100 p-4 rounded-2xl focus:border-red-500 outline-none transition-all text-sm font-bold text-neutral-700"
                      value={repairData.category}
                      onChange={e => setRepairData({...repairData, category: e.target.value})}
                    >
                      <option>General</option>
                      <option>Plumbing</option>
                      <option>Electrical</option>
                      <option>Painting</option>
                      <option>Carpentry</option>
                    </select>
                  </div>
                </div>
                <div className="flex gap-4 pt-4">
                  <button 
                    type="button" 
                    onClick={() => { setShowRepairForm(false); setPendingStatus(null); }}
                    className="flex-1 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest text-neutral-400 hover:bg-neutral-50 transition-all border border-neutral-100"
                  >
                    Abort
                  </button>
                  <button 
                    type="submit" 
                    className="flex-[2] bg-red-500 text-white font-black text-[10px] uppercase tracking-widest py-4 rounded-2xl shadow-xl shadow-red-500/20 active:scale-95 transition-all"
                  >
                    Confirm & Start Repair
                  </button>
                </div>
              </form>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

