const IntelligenceMetric: React.FC<{ label: string, value: string, icon: React.ReactNode, highlight?: boolean }> = ({ label, value, icon, highlight }) => (
  <div className={`p-10 rounded-[2.5rem] border bg-white shadow-sm transition-all hover:-translate-y-1 ${highlight ? 'border-red-100 ring-4 ring-red-500/5' : 'border-neutral-100'}`}>
