import React, { useState, useMemo } from 'react';
import { UserRole, Tenant, House, PaymentRecord, Expense, HouseStatus, Repair, MeterReading } from './types';
import { INITIAL_TENANTS, INITIAL_HOUSES, INITIAL_PAYMENTS } from './constants';
import { Layout } from './components/Layout';
import { CaretakerDashboard } from './components/CaretakerDashboard';
import { LandlordDashboard } from './components/LandlordDashboard';
import { TenantDashboard } from './components/TenantDashboard';
import { Users, ShieldCheck, Key, ArrowRight } from 'lucide-react';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [activeView, setActiveView] = useState<string>('dashboard');
  const [tenants, setTenants] = useState<Tenant[]>(INITIAL_TENANTS);
  const [houses, setHouses] = useState<House[]>(INITIAL_HOUSES);
  const [payments, setPayments] = useState<PaymentRecord[]>(INITIAL_PAYMENTS);
  const [expenses, setExpenses] = useState<Expense[]>([]);

  const handleAddTenant = (newTenant: Tenant) => {
    setTenants(prev => [...prev, newTenant]);
    setHouses(prev => prev.map(h => h.houseNumber === newTenant.houseNumber ? { ...h, status: HouseStatus.RENTED } : h));
  };

  const handleUpdateTenant = (updatedTenant: Tenant) => {
    setTenants(prev => prev.map(t => t.id === updatedTenant.id ? updatedTenant : t));
  };

  const handleUpdateBills = (tenantId: string, currentReading: number) => {
    setTenants(prev => prev.map(t => {
      if (t.id === tenantId) {
        const unitsUsed = Math.max(0, currentReading - t.bills.prevWaterReading);
        const waterCost = unitsUsed * 150;
        const newTotal = t.bills.rent + waterCost + t.bills.garbage;

        const newReading: MeterReading = {
          id: `mr-${Date.now()}`,
          date: new Date().toISOString().split('T')[0],
          reading: currentReading,
          unitsConsumed: unitsUsed,
          cost: waterCost
        };

        return { 
          ...t, 
          bills: { 
            ...t.bills, 
            water: waterCost, 
            prevWaterReading: t.bills.currWaterReading, // Cycle previous to current
            currWaterReading: currentReading,
            total: newTotal, 
            status: 'UNPAID' 
          },
          meterReadings: [newReading, ...(t.meterReadings || [])]
        };
      }
      return t;
    }));
  };

  const handlePayment = (payment: PaymentRecord) => {
    setPayments(prev => [payment, ...prev]);
    const tenant = tenants.find(t => t.id === payment.tenantId);
    if (tenant && (payment.type === 'RENT' || payment.type === 'TOTAL')) {
      setHouses(prev => prev.map(h => {
        if (h.houseNumber === tenant.houseNumber) {
          return { ...h, totalEarnings: h.totalEarnings + payment.amount };
        }
        return h;
      }));
    }

    setTenants(prev => prev.map(t => {
      if (t.id === payment.tenantId) {
        const bills = { ...t.bills };
        if (payment.type === 'RENT') bills.rent = Math.max(0, bills.rent - payment.amount);
        else if (payment.type === 'WATER') bills.water = Math.max(0, bills.water - payment.amount);
        else if (payment.type === 'GARBAGE') bills.garbage = Math.max(0, bills.garbage - payment.amount);
        else {
          let rem = payment.amount;
          const waterPay = Math.min(rem, bills.water);
          bills.water -= waterPay;
          rem -= waterPay;
          const garbagePay = Math.min(rem, bills.garbage);
          bills.garbage -= garbagePay;
          rem -= garbagePay;
          bills.rent = Math.max(0, bills.rent - rem);
        }
        bills.total = bills.rent + bills.water + bills.garbage;
        bills.status = bills.total <= 0 ? 'PAID' : 'PARTIAL';
        return { ...t, bills };
      }
      return t;
    }));
  };

  const handleHouseUpdate = (houseId: string, status: HouseStatus, repair?: Repair) => {
    setHouses(prev => prev.map(h => {
      if (h.id === houseId) {
        const newRepairs = repair ? [repair, ...h.repairs] : h.repairs;
        return { ...h, status, repairs: newRepairs };
      }
      return h;
    }));
  };

  const handleAddExpense = (expense: Expense) => {
    setExpenses(prev => [expense, ...prev]);
  };

  const handleSetRole = (newRole: UserRole) => {
    setRole(newRole);
    if (newRole === UserRole.TENANT) {
      setActiveView('profile');
    } else {
      setActiveView('dashboard');
    }
  };

  const renderContent = () => {
    if (role === UserRole.CARETAKER) {
      return (
        <CaretakerDashboard 
          tenants={tenants} 
          houses={houses}
          payments={payments}
          activeTab={activeView === 'dashboard' ? 'houses' : activeView as any}
          onAddTenant={handleAddTenant}
          onUpdateTenant={handleUpdateTenant}
          onUpdateBills={handleUpdateBills}
          onUpdateHouse={handleHouseUpdate}
          onLogPayment={handlePayment}
        />
      );
    }
    if (role === UserRole.LANDLORD) {
      return (
        <LandlordDashboard 
          tenants={tenants} 
          houses={houses}
          payments={payments}
          expenses={expenses}
          view={activeView}
          onAddExpense={handleAddExpense}
        />
      );
    }
    if (role === UserRole.TENANT) {
      const tenantPayments = payments
        .filter(p => p.tenantId === tenants[0].id)
        .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

      return (
        <TenantDashboard 
          tenant={tenants[0]} 
          payments={tenantPayments}
          onPay={handlePayment}
          initialTab={activeView === 'payments' ? 'payments' : 'profile'}
        />
      );
    }
    return null;
  };

  if (!role) {
    return (
      <div className="min-h-screen bg-neutral-900 flex flex-col items-center justify-center p-6 text-white overflow-hidden relative">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_50%,rgba(31,106,225,0.1),transparent)] pointer-events-none" />
        <div className="mb-12 text-center animate-fadeIn relative z-10">
          <h1 className="text-7xl font-royal mb-4 text-royal-500 drop-shadow-2xl">ROYAL FLATS</h1>
          <p className="text-neutral-400 uppercase tracking-[0.6em] text-[10px] font-black">Management Intelligence System</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 w-full max-w-6xl animate-slideUp relative z-10">
          <RoleCard title="Resident" icon={<Key className="w-10 h-10"/>} description="Pay rent via M-Pesa, track utility consumption, and request support." onClick={() => handleSetRole(UserRole.TENANT)} />
          <RoleCard title="Caretaker" icon={<ShieldCheck className="w-10 h-10"/>} description="Manage unit occupancy, update meters, and notify tenants of arrears." onClick={() => handleSetRole(UserRole.CARETAKER)} highlight />
          <RoleCard title="Owner" icon={<Users className="w-10 h-10"/>} description="Portfolio analytics, financial reports, and expense tracking." onClick={() => handleSetRole(UserRole.LANDLORD)} />
        </div>
      </div>
    );
  }

  return (
    <Layout 
      role={role} 
      onLogout={() => { setRole(null); setActiveView('dashboard'); }} 
      activeView={activeView} 
      onViewChange={setActiveView}
    >
      {renderContent()}
    </Layout>
  );
};

const RoleCard: React.FC<{ title: string, icon: React.ReactNode, description: string, onClick: () => void, highlight?: boolean }> = ({ title, icon, description, onClick, highlight }) => (
  <button 
    onClick={onClick} 
    className={`p-10 rounded-[3rem] border transition-all duration-500 text-left group relative overflow-hidden h-full flex flex-col ${highlight ? 'border-royal-500/30 bg-royal-500/5 hover:bg-royal-500/10 hover:border-royal-500 shadow-2xl shadow-royal-900/20' : 'border-neutral-800 bg-neutral-800/30 hover:bg-neutral-800 hover:border-neutral-600 shadow-xl'}`}
  >
    <div className={`mb-8 p-5 rounded-2xl inline-block ${highlight ? 'bg-royal-500/20 text-royal-500' : 'bg-neutral-700 text-neutral-400'} group-hover:scale-110 transition-transform duration-500`}>
      {icon}
    </div>
    <h3 className="text-3xl font-royal mb-4 text-white font-bold">{title} Portal</h3>
    <p className="text-neutral-400 text-sm leading-relaxed mb-8 flex-1 font-medium">{description}</p>
    <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-all duration-300 text-royal-500 transform translate-y-4 group-hover:translate-y-0">
      Access Intelligence System <ArrowRight size={14}/>
    </div>
  </button>
);

export default App;

