    setNewTenant({ name: '', email: '', houseNumber: '', idNumber: '', phoneNumber: '', nextOfKin: '', rent: 0 });
  };

  const handleApplyUpdate = (tenantId: string) => {
    const reading = pendingReadings[tenantId];
    if (reading === undefined) return;
    onUpdateBills(tenantId, reading);
    setUpdatedTenantId(tenantId);
    setPendingReadings(prev => {
      const next = { ...prev };
      delete next[tenantId];
      return next;
    });
    setTimeout(() => setUpdatedTenantId(null), 2000);
