                  const units = Math.max(0, displayReading - t.bills.prevWaterReading);
                  const cost = units * 150;

                  return (
                    <div key={t.id} className={`flex flex-col sm:flex-row items-center justify-between p-6 bg-neutral-50 rounded-[2.5rem] border transition-all ${isModified ? 'border-royal-500 ring-2 ring-royal-500/10' : 'border-neutral-100 hover:border-royal-200'}`}>
