          <div className="absolute top-0 right-0 p-8 opacity-10"><Home size={100}/></div>
          <div className="relative z-10">
             <h3 className="text-3xl font-royal font-black tracking-tight">Unit {house.houseNumber}</h3>
             <p className="text-neutral-400 text-xs uppercase font-black tracking-widest mt-1">{house.type} Profile</p>
          </div>
          <button onClick={onClose} className="relative z-20 p-4 bg-white/10 hover:bg-white/20 rounded-2xl transition-all cursor-pointer">
            <X size={24} />
