                    className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${activeViewTab === 'maintenance' ? 'bg-white text-royal-500 shadow-sm' : 'text-neutral-400 hover:text-neutral-600'}`}
                   >
                     Maintenance
                   </button>
                   <button 
                    onClick={() => setActiveViewTab('utility')}
