  const accentClass = isRented ? 'bg-green-500' : isVacant ? 'bg-amber-500' : 'bg-red-500';

  return (
    <div className={`bg-white p-8 rounded-[2.5rem] border-2 transition-all group relative overflow-hidden flex flex-col shadow-sm hover:shadow-xl hover:shadow-neutral-200/50 ${borderClass}`}>
      <div className={`absolute top-0 left-0 right-0 h-1.5 ${accentClass}`} />
      <div className="flex justify-between items-start mb-6">
        <div>
          <h3 className="text-3xl font-royal font-black text-neutral-800 tracking-tighter">{house.houseNumber}</h3>
          <p className="text-[10px] text-neutral-400 font-black uppercase tracking-widest mt-1.5">{house.type}</p>
        </div>
        <div className="flex flex-col items-end gap-2">
          <StatusBadge status={house.status} />
        </div>
      </div>

      {isRented && (
        <div className="mb-6 bg-green-50 p-4 rounded-2xl border border-green-100 animate-fadeIn">
          <span className="text-[9px] font-black text-green-600 uppercase tracking-widest block mb-1">Current Resident</span>
          <div className="flex items-center gap-2">
            <User size={14} className="text-green-500" />
            <span className="text-sm font-bold text-neutral-800">{tenantName || 'Registering...'}</span>
          </div>
