      className="w-full bg-neutral-50 border-2 border-neutral-100 p-4 rounded-2xl focus:border-royal-500 outline-none transition-all text-sm font-bold text-neutral-700" 
      value={value} 
      onChange={(e) => onChange(e.target.value)} 
    />
