                <IntelligenceMetric label="Exposure (Arrears)" value={`KES ${tenant.bills.total.toLocaleString()}`} icon={<AlertTriangle className="text-red-500" />} highlight />
                <IntelligenceMetric label="Next Cycle" value="Nov 1, 2024" icon={<Calendar className="text-royal-500" />} />
