          <div className="relative z-10">
             <h3 className="text-3xl font-royal font-black tracking-tight">Edit Resident Profile</h3>
             <p className="text-neutral-400 text-xs uppercase font-black tracking-widest mt-1">Updating ID: {tenant.id.slice(-6)}</p>
          </div>
          <button onClick={onClose} className="p-4 bg-white/10 hover:bg-white/20 rounded-2xl transition-all"><X size={24} /></button>
        </div>
        <form onSubmit={handleSubmit} className="p-12 grid grid-cols-1 md:grid-cols-2 gap-8">
          <InputGroup icon={<User size={16}/>} label="Full Name" placeholder="Full Name" value={formData.name} onChange={(val) => setFormData({...formData, name: val})} />
          <InputGroup icon={<Mail size={16}/>} label="Email Address" placeholder="email@example.com" value={formData.email} onChange={(val) => setFormData({...formData, email: val})} />
          <InputGroup icon={<Phone size={16}/>} label="Phone Number" placeholder="07XXXXXXXX" value={formData.phoneNumber} onChange={(val) => setFormData({...formData, phoneNumber: val})} />
          <InputGroup icon={<Users size={16}/>} label="Next of Kin" placeholder="Full Name & Contact" value={formData.nextOfKin} onChange={(val) => setFormData({...formData, nextOfKin: val})} />

          <div className="md:col-span-2 pt-10 flex gap-4">
            <button type="button" onClick={onClose} className="flex-1 py-5 rounded-2xl font-black text-xs uppercase tracking-widest text-neutral-400 hover:text-neutral-600 hover:bg-neutral-50 transition-all border border-neutral-200">Discard Changes</button>
            <button type="submit" className="flex-[2] py-5 rounded-2xl font-black text-xs uppercase tracking-widest text-white bg-royal-500 hover:bg-royal-600 shadow-2xl active:scale-95 transition-all flex items-center justify-center gap-2">Commit Updates <Save size={16}/></button>
          </div>
        </form>
      </div>
    </div>
  );
};

const InputGroup: React.FC<{ icon: React.ReactNode, label: string, placeholder: string, value: string, onChange: (val: string) => void, type?: string }> = ({ icon, label, placeholder, value, onChange, type = 'text' }) => (
