const StatusBadge: React.FC<{ status: HouseStatus }> = ({ status }) => {
  const variants = {
    [HouseStatus.RENTED]: 'bg-green-100 text-green-700 border-green-200',
    [HouseStatus.VACANT]: 'bg-amber-100 text-amber-700 border-amber-200',
