                      <th className="px-10 py-6 text-[11px] font-black text-neutral-400 uppercase tracking-widest text-center">Modality</th>
                      <th className="px-10 py-6 text-[11px] font-black text-neutral-400 uppercase tracking-widest text-right">Amount (KES)</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-neutral-50">
                    {payments.map(p => (
                      <tr key={p.id} className="hover:bg-neutral-50 transition-colors group">
                        <td className="px-10 py-6">
                           <div className="font-bold text-neutral-800">{new Date(p.date).toLocaleDateString()}</div>
                           <div className="text-[10px] text-neutral-400 font-bold uppercase">{p.type}</div>
                        </td>
                        <td className="px-10 py-6">
                          <div className="font-mono text-xs text-neutral-500 group-hover:text-royal-500 transition-colors">{p.reference}</div>
                        </td>
                        <td className="px-10 py-6 text-center">
                          <span className="bg-neutral-100 text-neutral-600 px-3 py-1.5 rounded-xl text-[9px] font-black uppercase border border-neutral-200">{p.method}</span>
                        </td>
                        <td className="px-10 py-6 text-right font-black text-neutral-900 group-hover:text-green-600 transition-colors">KES {p.amount.toLocaleString()}</td>
                      </tr>
                    ))}
                    {payments.length === 0 && <tr><td colSpan={4} className="p-32 text-center text-neutral-300 italic">No historical financial footprints.</td></tr>}
                  </tbody>
               </table>
            </div>
          )}
          {activeTab === 'analysis' && (
            <div className="bg-neutral-900 p-20 rounded-[4rem] text-center space-y-12 shadow-2xl relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-royal-500 to-transparent" />
              <div className="relative z-10 max-w-xl mx-auto space-y-6">
                  <div className="w-20 h-20 bg-royal-500/10 rounded-3xl flex items-center justify-center text-royal-500 mx-auto border border-royal-500/20 shadow-inner">
                    <Activity size={40} className={loadingAI ? 'animate-pulse' : ''} />
                  </div>
                  <h4 className="text-white text-3xl font-royal font-black tracking-tight">AI Reliability Auditor</h4>
                  <p className="text-neutral-400 text-lg leading-relaxed">System-generated behavioral analysis based on payment periodicity and consumption trends.</p>

                  {aiInsight ? (
                    <div className="mt-12 bg-white/5 p-12 rounded-[3rem] border border-white/10 text-left animate-fadeIn shadow-2xl relative">
                       <div className="absolute -top-4 left-10 bg-royal-500 text-white text-[8px] font-black px-3 py-1.5 rounded-lg uppercase tracking-[0.2em]">Audit Result</div>
                       <p className="text-royal-100 italic leading-relaxed text-xl font-royal">"{aiInsight}"</p>
                       <div className="flex gap-4 mt-10 border-t border-white/5 pt-8">
                          <button onClick={handleRunAnalysis} className="text-royal-400 text-[10px] font-black uppercase tracking-widest hover:text-white transition-all flex items-center gap-2">
                             <RefreshCw size={14}/> Re-Analyze Engine
                          </button>
                       </div>
                    </div>
                  ) : (
                    <button onClick={handleRunAnalysis} disabled={loadingAI} className="mt-12 bg-royal-500 text-white px-12 py-6 rounded-3xl font-black text-xs uppercase tracking-[0.3em] hover:bg-royal-600 shadow-2xl shadow-royal-500/20 active:scale-95 transition-all flex items-center justify-center gap-3 mx-auto">
                      {loadingAI ? <Activity className="animate-spin" size={18}/> : <ShieldCheck size={18}/>}
                      {loadingAI ? 'Scanning History...' : 'Run Audit Sequence'}
                    </button>
                  )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const ModalTab: React.FC<{ active: boolean, onClick: () => void, label: string, icon: React.ReactNode }> = ({ active, onClick, label, icon }) => (
  <button onClick={onClick} className={`px-6 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 ${active ? 'bg-royal-500 text-white shadow-xl shadow-royal-500/20' : 'text-neutral-500 hover:text-neutral-300'}`}>
    {icon} {label}
  </button>
);

const IntelligenceMetric: React.FC<{ label: string, value: string, icon: React.ReactNode, highlight?: boolean }> = ({ label, value, icon, highlight }) => (
  <div className={`p-10 rounded-[2.5rem] border bg-white shadow-sm transition-all hover:-translate-y-1 ${highlight ? 'border-red-100 ring-4 ring-red-500/5' : 'border-neutral-100'}`}>
    <div className="flex items-center gap-3 mb-4">
      <div className="p-3 bg-neutral-50 rounded-2xl">{icon}</div>
      <span className="text-[10px] uppercase font-black tracking-widest text-neutral-400">{label}</span>
    </div>
    <div className={`text-2xl font-bold font-royal tracking-tight truncate ${highlight ? 'text-red-500' : 'text-neutral-800'}`}>{value}</div>
  </div>
);

const FinancialLine: React.FC<{ label: string, value: number, max: number, color: string }> = ({ label, value, max, color }) => (
  <div className="space-y-2">
    <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest">
      <span className="text-neutral-400">{label}</span>
      <span className="text-neutral-800">KES {value.toLocaleString()}</span>
    </div>
    <div className="h-1.5 w-full bg-neutral-100 rounded-full overflow-hidden">
      <div className={`h-full ${color} rounded-full transition-all duration-1000`} style={{ width: `${Math.min(100, (value/max)*100)}%` }} />
    </div>
  </div>
);

import React, { useState, useEffect, useMemo } from 'react';
import { Tenant, House, HouseStatus, PaymentRecord, Repair, MeterReading } from '../types';
import { 
  UserPlus, Droplets, Send, Wrench, RefreshCw, X, User, Phone, Mail, 
  Hash, Home, CheckCircle2, CircleDashed, Hammer, Users, AlertTriangle, Clock, 
  History, DollarSign, Activity, Eye, Search, MapPin, ArrowRight, Save, Smartphone,
  Receipt, Calendar, ChevronRight, Filter, RotateCcw, Check, ShieldCheck, CreditCard,
  FileText, TrendingUp, MoreHorizontal, BellRing, UserCheck, Wallet, Edit3, Plus,
  ChevronDown, ArrowUp, Zap
} from 'lucide-react';
import { generateTenantNotification, analyzeTenantFinancials } from '../services/geminiService';

interface Props {
  tenants: Tenant[];
  houses: House[];
  payments: PaymentRecord[];
  onAddTenant: (t: Tenant) => void;
  onUpdateTenant: (t: Tenant) => void;
  onUpdateBills: (id: string, currentReading: number) => void;
  onBulkUpdateBills?: (readings: Record<string, number>) => void;
  onUpdateHouse: (id: string, status: HouseStatus, repair?: Repair) => void;
  onLogPayment?: (payment: PaymentRecord) => void;
  onAddGeneralMaintenance?: (repair: any) => void;
  activeTab?: string;
}

export const CaretakerDashboard: React.FC<Props> = ({ 
  tenants, houses, payments, onAddTenant, onUpdateTenant, onUpdateBills, onBulkUpdateBills, onUpdateHouse, onLogPayment,
  onAddGeneralMaintenance, activeTab: propTab 
}) => {
  const [activeTab, setActiveTab] = useState<'houses' | 'tenants' | 'billing'>('houses');
  const [showAddModal, setShowAddModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showLogPaymentModal, setShowLogPaymentModal] = useState(false);
  const [showMaintenanceModal, setShowMaintenanceModal] = useState(false);
  const [selectedHouse, setSelectedHouse] = useState<House | null>(null);
  const [selectedTenant, setSelectedTenant] = useState<Tenant | null>(null);
  const [tenantToEdit, setTenantToEdit] = useState<Tenant | null>(null);
  const [loadingAI, setLoadingAI] = useState<string | null>(null);
  const [updatedTenantIds, setUpdatedTenantIds] = useState<Set<string>>(new Set());

  const [pendingReadings, setPendingReadings] = useState<Record<string, number>>({});
  const [searchQuery, setSearchQuery] = useState('');

  const [billFilterType, setBillFilterType] = useState<string>('ALL');
  const [billFilterMethod, setBillFilterMethod] = useState<string>('ALL');
  const [billStartDate, setBillStartDate] = useState<string>('');
  const [billEndDate, setBillEndDate] = useState<string>('');

  useEffect(() => {
    if (propTab) {
      if (propTab === 'houses' || propTab === 'properties') setActiveTab('houses');
      else if (propTab === 'tenants') setActiveTab('tenants');
      else if (propTab === 'billing' || propTab === 'payments') setActiveTab('billing');
    }
  }, [propTab]);

  const [newTenant, setNewTenant] = useState({
    name: '', email: '', houseNumber: '', idNumber: '', phoneNumber: '', nextOfKin: '', rent: 0
  });

  const filteredCollections = useMemo(() => {
    return payments.filter(p => {
      const matchesType = billFilterType === 'ALL' || p.type === billFilterType;
      const matchesMethod = billFilterMethod === 'ALL' || p.method === billFilterMethod;
      const paymentDate = new Date(p.date).getTime();
      const start = billStartDate ? new Date(billStartDate).getTime() : 0;
      const end = billEndDate ? new Date(billEndDate).getTime() : Infinity;
      const matchesDate = paymentDate >= start && paymentDate <= (end + 86400000);
      return matchesType && matchesMethod && matchesDate;
    });
  }, [payments, billFilterType, billFilterMethod, billStartDate, billEndDate]);

  const meteringTenants = useMemo(() => {
    return tenants.filter(t => 
      t.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
      t.houseNumber.toLowerCase().includes(searchQuery.toLowerCase())
    ).sort((a, b) => a.houseNumber.localeCompare(b.houseNumber));
  }, [tenants, searchQuery]);

  const handleSendReminder = async (tenant: Tenant) => {
    setLoadingAI(tenant.id);
    try {
      const message = await generateTenantNotification(tenant.name, tenant.bills.total);
      alert(`AI Reminder for ${tenant.name}:\n\n"${message}"\n\nNotification sent to ${tenant.phoneNumber}`);
    } catch (err) { console.error(err); }
    finally { setLoadingAI(null); }
  };

  const handleRegisterTenant = (e: React.FormEvent) => {
    e.preventDefault();
    const tenant: Tenant = {
      id: `t-${Date.now()}`,
      name: newTenant.name,
      email: newTenant.email,
      houseNumber: newTenant.houseNumber,
      idNumber: newTenant.idNumber,
      phoneNumber: newTenant.phoneNumber,
      nextOfKin: newTenant.nextOfKin,
      joinDate: new Date().toISOString().split('T')[0],
      bills: { 
        rent: newTenant.rent, 
        water: 0, 
        prevWaterReading: 0,
        currWaterReading: 0,
        garbage: 500, 
        total: newTenant.rent + 500, 
        status: 'UNPAID' 
      },
      meterReadings: []
    };
    onAddTenant(tenant);
    setShowAddModal(false);
    setNewTenant({ name: '', email: '', houseNumber: '', idNumber: '', phoneNumber: '', nextOfKin: '', rent: 0 });
  };

  const handleApplyUpdate = (tenantId: string) => {
    const reading = pendingReadings[tenantId];
    if (reading === undefined) return;
    onUpdateBills(tenantId, reading);
    setUpdatedTenantIds(prev => new Set(prev).add(tenantId));
    setPendingReadings(prev => {
      const next = { ...prev };
      delete next[tenantId];
      return next;
    });
    setTimeout(() => {
      setUpdatedTenantIds(prev => {
        const next = new Set(prev);
        next.delete(tenantId);
        return next;
      });
    }, 2000);
  };

  const handleCommitAllReadings = () => {
    if (onBulkUpdateBills) {
      onBulkUpdateBills(pendingReadings);
      const affectedIds = Object.keys(pendingReadings);
      setUpdatedTenantIds(new Set(affectedIds));
      setPendingReadings({});
      setTimeout(() => setUpdatedTenantIds(new Set()), 2000);
    } else {
      Object.keys(pendingReadings).forEach(id => handleApplyUpdate(id));
    }
  };

  const handleEditClick = (tenant: Tenant) => {
    setTenantToEdit(tenant);
    setShowEditModal(true);
  };

  const handleManualPayment = (payment: PaymentRecord) => {
    if (onLogPayment) {
      onLogPayment(payment);
      setShowLogPaymentModal(false);
    }
  };

  const handleGeneralMaintenance = (repair: any) => {
    if (onAddGeneralMaintenance) {
      onAddGeneralMaintenance(repair);
    } else if (repair.houseId && repair.houseId !== 'common') {
      onUpdateHouse(repair.houseId, HouseStatus.UNDER_REPAIR, {
        id: repair.id,
        date: repair.date,
        description: repair.description,
        cost: repair.cost,
        category: repair.category
      });
    }
    setShowMaintenanceModal(false);
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      {showAddModal && <AddTenantModal houses={houses} newTenant={newTenant} setNewTenant={setNewTenant} onClose={() => setShowAddModal(false)} onSubmit={handleRegisterTenant} />}
      {showLogPaymentModal && <LogPaymentModal tenants={tenants} onClose={() => setShowLogPaymentModal(false)} onSubmit={handleManualPayment} />}
      {showMaintenanceModal && <LogGeneralMaintenanceModal houses={houses} onClose={() => setShowMaintenanceModal(false)} onSubmit={handleGeneralMaintenance} />}
      {showEditModal && tenantToEdit && (
        <EditTenantModal 
          tenant={tenantToEdit} 
          onClose={() => { setShowEditModal(false); setTenantToEdit(null); }} 
          onSubmit={(updated) => { 
            onUpdateTenant(updated); 
            setShowEditModal(false); 
            setTenantToEdit(null);
            if (selectedTenant && selectedTenant.id === updated.id) {
               setSelectedTenant(updated);
            }
          }} 
        />
      )}
      {selectedHouse && (
        <HouseDetailModal 
          house={selectedHouse} 
          onClose={() => setSelectedHouse(null)} 
          onUpdateStatus={(status, repair) => {
            onUpdateHouse(selectedHouse.id, status, repair);
            setSelectedHouse({...selectedHouse, status, repairs: repair ? [repair, ...selectedHouse.repairs] : selectedHouse.repairs});
          }}
          currentTenant={tenants.find(t => t.houseNumber === selectedHouse.houseNumber)} 
          onViewTenant={(t) => {
            setSelectedHouse(null);
            setSelectedTenant(t);
          }}
        />
      )}
      {selectedTenant && <TenantIntelligenceModal tenant={selectedTenant} payments={payments.filter(p => p.tenantId === selectedTenant.id)} onClose={() => setSelectedTenant(null)} onNotify={() => handleSendReminder(selectedTenant)} onEdit={() => handleEditClick(selectedTenant)} />}

      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-3xl font-royal text-neutral-900 font-bold">Caretaker Operations</h2>
          <p className="text-neutral-400 text-sm mt-1">Daily unit management and property logistics</p>
        </div>
        <div className="flex bg-neutral-100 p-1.5 rounded-2xl border border-neutral-200 shadow-sm">
          {(['houses', 'tenants', 'billing'] as const).map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-white text-royal-500 shadow-sm' : 'text-neutral-400 hover:text-neutral-600'}`}>
              {tab === 'houses' ? 'Properties' : tab === 'billing' ? 'Collections' : tab.charAt(0).toUpperCase() + tab.slice(1)}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'houses' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {houses.map(house => (
            <UnitCard 
              key={house.id} 
              house={house} 
              onView={() => setSelectedHouse(house)} 
              tenantName={tenants.find(t => t.houseNumber === house.houseNumber)?.name}
            />
          ))}
          <button onClick={() => setShowAddModal(true)} className="border-2 border-dashed border-neutral-200 rounded-[2.5rem] flex flex-col items-center justify-center p-12 text-neutral-400 hover:border-royal-400 hover:text-royal-500 hover:bg-royal-50 transition-all group min-h-[300px] shadow-sm">
            <div className="bg-neutral-50 group-hover:bg-royal-100 p-6 rounded-3xl mb-4 transition-colors"><UserPlus size={40} /></div>
            <span className="font-black text-xs uppercase tracking-widest">Register Resident</span>
          </button>
        </div>
      )}

      {activeTab === 'tenants' && (
        <div className="bg-white rounded-[2.5rem] border border-neutral-200 shadow-sm overflow-hidden animate-slideUp">
          <div className="p-8 border-b border-neutral-100 flex justify-between items-center">
             <h3 className="font-bold text-lg text-neutral-800">Resident Registry</h3>
             <div className="relative flex gap-3">
                <div className="relative">
                   <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-neutral-400" />
                   <input type="text" placeholder="Search residents..." className="pl-9 pr-4 py-2 bg-neutral-50 border border-neutral-200 rounded-xl text-xs outline-none focus:border-royal-500 transition-all" />
                </div>
                <button onClick={() => setShowAddModal(true)} className="bg-royal-500 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 hover:bg-royal-600 transition-all shadow-lg shadow-royal-500/20">
                   <Plus size={14}/> Add New
                </button>
             </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-neutral-50 border-b">
                <tr>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Resident</th>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Unit No</th>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Last Payment</th>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Bill Status</th>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-neutral-50">
                {tenants.map(t => {
                  const tPayments = payments.filter(p => p.tenantId === t.id).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
                  const lastPayment = tPayments[0];

                  return (
                    <tr key={t.id} className="hover:bg-neutral-50 transition-all group">
                      <td className="px-8 py-6">
                        <div className="font-bold text-neutral-800 group-hover:text-royal-500 transition-colors">{t.name}</div>
                        <div className="text-[10px] text-neutral-400 font-medium tracking-tight flex items-center gap-1"><Phone size={10}/> {t.phoneNumber}</div>
                      </td>
                      <td className="px-8 py-6 font-bold text-neutral-600">{t.houseNumber}</td>
                      <td className="px-8 py-6">
                        {lastPayment ? (
                          <div>
                            <div className="text-xs font-black text-neutral-800">KES {lastPayment.amount.toLocaleString()}</div>
                            <div className="text-[9px] text-neutral-400 font-bold uppercase">{new Date(lastPayment.date).toLocaleDateString()}</div>
                          </div>
                        ) : (
                          <span className="text-[10px] text-neutral-300 italic font-medium">No records</span>
                        )}
                      </td>
                      <td className="px-8 py-6"><BillStatusBadge status={t.bills.status} /></td>
                      <td className="px-8 py-6 text-right">
                        <div className="flex justify-end gap-3">
                          <button onClick={() => setSelectedTenant(t)} className="p-2.5 bg-neutral-100 hover:bg-neutral-200 text-neutral-500 rounded-xl transition-all"><Eye size={16} /></button>
                          <button onClick={() => handleEditClick(t)} className="p-2.5 bg-neutral-100 hover:bg-royal-50 text-neutral-500 hover:text-royal-500 rounded-xl transition-all"><Edit3 size={16} /></button>
                          <button onClick={() => handleSendReminder(t)} disabled={loadingAI === t.id} className="inline-flex items-center gap-2 bg-royal-500 hover:bg-royal-600 text-white px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-royal-500/20 disabled:opacity-50 active:scale-95 transition-all">
                            {loadingAI === t.id ? <Activity className="animate-spin" size={14}/> : <Send size={14}/>} Notify
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'billing' && (
        <div className="space-y-10">
          <button 
            onClick={() => setShowLogPaymentModal(true)}
            className="fixed bottom-10 right-10 w-16 h-16 bg-royal-500 text-white rounded-full shadow-2xl flex items-center justify-center hover:bg-royal-600 hover:scale-110 active:scale-95 transition-all z-50 border-4 border-white group"
            title="Log Manual Payment"
          >
            <Plus size={32} className="group-hover:rotate-90 transition-transform duration-300" />
          </button>

          <div className="bg-white rounded-[3rem] border border-neutral-200 shadow-xl overflow-hidden animate-slideUp">
            <div className="bg-neutral-900 p-10 text-white flex flex-col md:flex-row justify-between items-start md:items-center gap-6 relative overflow-hidden">
               <div className="absolute top-0 right-0 p-10 opacity-5 text-royal-500"><Droplets size={200} /></div>
               <div className="relative z-10">
                  <div className="flex items-center gap-3 mb-2">
                     <span className="bg-royal-500 text-white text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-full shadow-lg shadow-royal-500/20">Monthly Billing Cycle</span>
                     <span className="text-neutral-400 text-xs font-bold uppercase">Rate: 150/unit</span>
                  </div>
                  <h3 className="text-4xl font-royal font-black tracking-tight">Utility Metering Workstation</h3>
                  <p className="text-neutral-500 text-sm mt-1">Audit and record consumption across all {tenants.length} active units</p>
               </div>

               <div className="flex items-center gap-4 relative z-10">
                  <div className="relative">
                    <Search size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-neutral-500" />
                    <input 
                      type="text" 
                      placeholder="Find Unit..." 
                      value={searchQuery}
                      onChange={e => setSearchQuery(e.target.value)}
                      className="bg-white/5 border border-white/10 pl-12 pr-6 py-4 rounded-2xl text-sm font-bold focus:bg-white/10 transition-all outline-none w-64" 
                    />
                  </div>
                  {Object.keys(pendingReadings).length > 0 && (
                    <button 
                      onClick={handleCommitAllReadings}
                      className="bg-royal-500 hover:bg-royal-600 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3 shadow-2xl shadow-royal-500/20 animate-pulse"
                    >
                      <Zap size={18} /> Commit {Object.keys(pendingReadings).length} Readings
                    </button>
                  )}
               </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-neutral-50 border-b border-neutral-100">
                  <tr>
                    <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Suite / Resident</th>
                    <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Previous Record</th>
                    <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest">New Meter Entry</th>
                    <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Net Consumption</th>
                    <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest text-right">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-neutral-50">
                  {meteringTenants.map(t => {
                    const pendingValue = pendingReadings[t.id];
                    const displayReading = pendingValue !== undefined ? pendingValue : t.bills.currWaterReading;
                    const isPending = pendingValue !== undefined;
                    const units = Math.max(0, displayReading - t.bills.currWaterReading);
                    const cost = units * 150;
                    const isSuccess = updatedTenantIds.has(t.id);

                    return (
                      <tr key={t.id} className={`transition-all hover:bg-neutral-50/50 group ${isPending ? 'bg-royal-50/30' : ''}`}>
                        <td className="px-10 py-8">
                           <div className="flex items-center gap-4">
                              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-royal font-black text-lg transition-all ${isPending ? 'bg-royal-500 text-white shadow-lg' : 'bg-neutral-100 text-neutral-400 group-hover:bg-neutral-200'}`}>
                                 {t.houseNumber}
