const HouseDetailModal: React.FC<{ house: House, onClose: () => void, currentTenant?: Tenant, onUpdateStatus: (s: HouseStatus, r?: Repair) => void, onViewTenant?: (t: Tenant) => void }> = ({ house, onClose, currentTenant, onUpdateStatus, onViewTenant }) => {
