                        <td className="px-10 py-8">
                           <div className="bg-neutral-100 px-4 py-2 rounded-xl inline-block">
                              <span className="text-neutral-500 text-xs font-mono font-bold">{t.bills.currWaterReading}</span>
                              <span className="text-[8px] font-black text-neutral-400 uppercase ml-2">Units</span>
                           </div>
                        </td>
                        <td className="px-10 py-8">
                           <div className="relative w-40">
                             <input 
                                type="number" 
                                className={`w-full bg-white border-2 p-4 rounded-2xl text-center font-black text-lg outline-none transition-all ${isSuccess ? 'border-green-500 bg-green-50' : isPending ? 'border-royal-500 ring-4 ring-royal-500/5' : 'border-neutral-200 hover:border-neutral-300'}`}
                                value={displayReading}
                                min={t.bills.currWaterReading}
                                onChange={(e) => setPendingReadings(prev => ({ ...prev, [t.id]: Number(e.target.value) }))}
                             />
                             {isPending && (
                               <button 
                                 onClick={() => handleApplyUpdate(t.id)}
                                 className="absolute -right-12 top-1/2 -translate-y-1/2 p-3 bg-royal-500 text-white rounded-xl shadow-lg hover:scale-110 active:scale-90 transition-all"
                               >
                                 <Save size={16}/>
                               </button>
                             )}
                           </div>
                        </td>
                        <td className="px-10 py-8">
                           {units > 0 ? (
                             <div className="animate-fadeIn">
                                <div className="flex items-center gap-1.5 text-cyan-600 font-bold text-sm">
                                   <ArrowUp size={14}/> {units} Units
                                </div>
                                <div className="text-[10px] font-black text-neutral-900 uppercase">KES {cost.toLocaleString()}</div>
                             </div>
                           ) : (
                             <span className="text-[10px] text-neutral-300 font-bold uppercase italic">No change</span>
                           )}
                        </td>
                        <td className="px-10 py-8 text-right">
                           {isSuccess ? (
                             <div className="inline-flex items-center gap-2 bg-green-100 text-green-700 px-4 py-2 rounded-full font-black text-[10px] uppercase border border-green-200 animate-bounce">
                                <Check size={14}/> Logged
                             </div>
                           ) : isPending ? (
                             <div className="inline-flex items-center gap-2 bg-royal-100 text-royal-700 px-4 py-2 rounded-full font-black text-[10px] uppercase border border-royal-200">
                                <Activity size={14} className="animate-pulse"/> Pending
                             </div>
                           ) : (
                             <div className="text-[10px] font-black text-neutral-300 uppercase italic">Awaiting Cycle</div>
                           )}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
            <div className="bg-white p-10 rounded-[3rem] border border-neutral-200 shadow-sm overflow-hidden">
              <div className="flex justify-between items-center mb-8">
                 <h3 className="text-xl font-bold flex items-center gap-3"><History className="text-royal-500" /> Latest Collections</h3>
                 <button onClick={() => setActiveTab('tenants')} className="text-royal-500 text-[10px] font-black uppercase tracking-widest hover:underline">Full Registry &rarr;</button>
              </div>
              <div className="space-y-4 max-h-[400px] overflow-y-auto scrollbar-hide">
                {filteredCollections.slice(0, 10).map(p => {
                    const tenant = tenants.find(t => t.id === p.tenantId);
                    return (
                      <div key={p.id} className="flex items-center justify-between p-5 bg-neutral-50 rounded-2xl border border-neutral-100 hover:border-royal-200 transition-all">
                        <div className="flex items-center gap-4">
                          <div className={`p-2.5 bg-white rounded-xl shadow-sm border border-neutral-100 ${p.method === 'Cash' ? 'text-amber-500' : 'text-green-500'}`}>
                             {p.method === 'M-Pesa' ? <Smartphone size={16}/> : p.method === 'Bank' ? <CreditCard size={16}/> : <Wallet size={16}/>}
                          </div>
                          <div>
                            <div className="font-bold text-neutral-800 text-sm">{tenant?.name || 'Unknown'}</div>
                            <div className="text-[9px] text-neutral-400 font-black uppercase tracking-widest">Unit {tenant?.houseNumber} • {p.type} • {new Date(p.date).toLocaleDateString()}</div>
                          </div>
                        </div>
                        <div className="text-right">
                          <div className="font-black text-neutral-900">KES {p.amount.toLocaleString()}</div>
                          <div className="text-[8px] text-neutral-400 font-mono uppercase">{p.reference}</div>
                        </div>
                      </div>
                    );
                  })}
              </div>
            </div>

            <div className="bg-neutral-900 text-white p-10 rounded-[3rem] shadow-2xl relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-10 opacity-0 group-hover:opacity-10 transition-opacity duration-700 text-royal-500"><Wrench size={160} /></div>
              <h3 className="text-xl font-bold mb-8 flex items-center gap-3 font-royal text-royal-100"><RefreshCw className="text-royal-500" /> Maintenance Logs</h3>
              <div className="space-y-4 max-h-[400px] overflow-y-auto scrollbar-hide">
                <MaintenanceItem date="Today" task="Front Gate Calibration" cost={4500} house="External" />
                <MaintenanceItem date="Yesterday" task="Kitchen Sink B4 Repair" cost={8200} house="B4" />
                <MaintenanceItem date="12th Sep" task="Corridor Lighting" cost={1500} house="Common Areas" />
              </div>
              <button 
                onClick={() => setShowMaintenanceModal(true)}
                className="w-full mt-10 bg-royal-500 text-white py-5 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-royal-600 shadow-xl shadow-royal-500/20 active:scale-95 transition-all"
              >
                Log Maintenance Event
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const UnitCard: React.FC<{ house: House, onView: any, tenantName?: string }> = ({ house, onView, tenantName }) => {
  const isRented = house.status === HouseStatus.RENTED;
  const isVacant = house.status === HouseStatus.VACANT;
  const borderClass = isRented ? 'border-green-100 hover:border-green-300' : isVacant ? 'border-amber-100 hover:border-amber-300' : 'border-red-100 hover:border-red-300';
  const accentClass = isRented ? 'bg-green-500' : isVacant ? 'bg-amber-500' : 'bg-red-500';

  return (
    <div className={`bg-white p-8 rounded-[2.5rem] border-2 transition-all group relative overflow-hidden flex flex-col shadow-sm hover:shadow-xl hover:shadow-neutral-200/50 ${borderClass}`}>
      <div className={`absolute top-0 left-0 right-0 h-1.5 ${accentClass}`} />
      <div className="flex justify-between items-start mb-6">
        <div>
          <h3 className="text-3xl font-royal font-black text-neutral-800 tracking-tighter">{house.houseNumber}</h3>
          <p className="text-[10px] text-neutral-400 font-black uppercase tracking-widest mt-1.5">{house.type}</p>
        </div>
        <div className="flex flex-col items-end gap-2">
          <StatusBadge status={house.status} />
        </div>
      </div>

      {isRented && (
        <div className="mb-6 bg-green-50 p-4 rounded-2xl border border-green-100 animate-fadeIn">
          <span className="text-[9px] font-black text-green-600 uppercase tracking-widest block mb-1">Current Resident</span>
          <div className="flex items-center gap-2">
            <User size={14} className="text-green-500" />
            <span className="text-sm font-bold text-neutral-800">{tenantName || 'Registering...'}</span>
          </div>
        </div>
      )}

      <div className="space-y-4 mb-6 flex-1">
        <div className="bg-neutral-50 p-4 rounded-2xl border border-neutral-100 flex justify-between items-center transition-all group-hover:bg-white group-hover:shadow-sm">
           <span className="text-[10px] text-neutral-400 font-black uppercase tracking-widest">Lifetime Yield</span>
           <span className="font-black text-neutral-900 tracking-tight">KES {house.totalEarnings.toLocaleString()}</span>
        </div>
        <div className="flex justify-between text-xs items-center px-1">
          <span className="text-neutral-400 font-bold uppercase tracking-tight">Service Logs</span>
          <span className="font-black text-amber-600">{house.repairs.length} Records</span>
        </div>
      </div>
      <button 
        onClick={onView} 
        className="w-full py-4 bg-neutral-100 hover:bg-royal-500 hover:text-white text-neutral-600 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all flex items-center justify-center gap-2 group-hover:shadow-lg group-hover:shadow-royal-500/10"
      >
        View Details & Status <Eye size={14} />
      </button>
    </div>
  );
};

const UnitStatusBtn: React.FC<{ active: boolean, onClick: () => void, color: 'green' | 'amber' | 'red', label: string, icon: React.ReactNode }> = ({ active, onClick, color, label, icon }) => {
  const variants = {
    green: active ? 'bg-green-500 text-white shadow-lg shadow-green-500/20' : 'text-neutral-400 hover:text-green-600 hover:bg-green-50 border border-neutral-100',
    amber: active ? 'bg-amber-500 text-white shadow-lg shadow-amber-500/20' : 'text-neutral-400 hover:text-amber-600 hover:bg-amber-50 border border-neutral-100',
    red: active ? 'bg-red-500 text-white shadow-lg shadow-red-500/20' : 'text-neutral-400 hover:text-red-600 hover:bg-red-50 border border-neutral-100',
  };
  return (
    <button 
      onClick={(e) => { e.stopPropagation(); onClick(); }} 
      className={`flex flex-col items-center justify-center py-4 rounded-2xl transition-all gap-1.5 flex-1 ${variants[color]}`}
    >
      {icon}
      <span className="text-[8px] font-black uppercase tracking-tight">{label}</span>
    </button>
  );
};

const LogPaymentModal: React.FC<{ tenants: Tenant[], onClose: () => void, onSubmit: (p: PaymentRecord) => void }> = ({ tenants, onClose, onSubmit }) => {
  const [formData, setFormData] = useState({
    tenantId: '',
    amount: '',
    type: 'RENT' as PaymentRecord['type'],
    reference: '',
    method: 'M-Pesa'
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.tenantId) return;

    onSubmit({
      id: `pay-${Date.now()}`,
      tenantId: formData.tenantId,
      amount: Number(formData.amount),
      date: new Date().toISOString(),
      type: formData.type,
      reference: formData.reference || `STAFF-${Math.random().toString(36).substring(7).toUpperCase()}`,
      method: formData.method
    });
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-neutral-900/95 backdrop-blur-md animate-fadeIn">
      <div className="bg-white w-full max-w-xl rounded-[3.5rem] shadow-2xl overflow-hidden animate-slideUp">
        <div className="bg-neutral-900 p-10 text-white flex justify-between items-center relative overflow-hidden">
          <div className="absolute top-0 right-0 p-8 opacity-10"><CreditCard size={100}/></div>
          <div className="relative z-10">
             <h3 className="text-3xl font-royal font-black tracking-tight">Record Collection</h3>
             <p className="text-neutral-400 text-xs uppercase font-black tracking-widest mt-1">Manual Ledger Entry</p>
          </div>
          <button onClick={onClose} className="p-4 bg-white/10 hover:bg-white/20 rounded-2xl transition-all"><X size={24} /></button>
        </div>
        <form onSubmit={handleSubmit} className="p-12 space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-neutral-400 uppercase tracking-widest flex items-center gap-2"><User size={14}/> Resident Selection</label>
            <div className="relative">
              <select 
                required 
                className="w-full bg-neutral-50 border-2 border-neutral-100 p-4 rounded-2xl focus:border-royal-500 outline-none transition-all text-sm font-bold text-neutral-700 appearance-none" 
                value={formData.tenantId} 
                onChange={(e) => setFormData({...formData, tenantId: e.target.value})}
              >
                <option value="">Select a Resident</option>
