const HouseDetailModal: React.FC<{ house: House, onClose: () => void, currentTenant?: Tenant, onUpdateStatus: (s: HouseStatus, r?: Repair) => void, onViewTenant?: (t: Tenant) => void }> = ({ house, onClose, currentTenant, onUpdateStatus, onViewTenant }) => {
  const [pendingStatus, setPendingStatus] = useState<HouseStatus | null>(null);
  const [showRepairForm, setShowRepairForm] = useState(false);
  const [repairData, setRepairData] = useState({ description: '', cost: '', category: 'General' });
  const [activeViewTab, setActiveViewTab] = useState<'maintenance' | 'utility'>('maintenance');

  const handleStatusCommit = () => {
    if (!pendingStatus) return;
    if (pendingStatus === HouseStatus.UNDER_REPAIR) {
      setShowRepairForm(true);
    } else {
      onUpdateStatus(pendingStatus);
      setPendingStatus(null);
    }
  };

  const handleRepairSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const repair: Repair = {
      id: `r-${Date.now()}`,
      date: new Date().toISOString().split('T')[0],
      description: repairData.description,
      cost: Number(repairData.cost),
      category: repairData.category
    };
    onUpdateStatus(HouseStatus.UNDER_REPAIR, repair);
    setShowRepairForm(false);
    setPendingStatus(null);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-neutral-900/90 backdrop-blur-sm animate-fadeIn">
      <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-slideUp border border-neutral-200 flex flex-col max-h-[90vh]">
