             <h3 className="text-3xl font-royal font-black tracking-tight">Unit {house.houseNumber}</h3>
             <p className="text-neutral-400 text-xs uppercase font-black tracking-widest mt-1">{house.type} Profile</p>
          </div>
          {/* Enhanced Close Button for Visibility */}
