        </div>

        <div className="p-10 space-y-8 overflow-y-auto scrollbar-hide">
          {!showRepairForm ? (
            <>
              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-1">
                  <p className="text-[10px] font-black text-neutral-400 uppercase tracking-widest">Current Status</p>
                  <StatusBadge status={house.status} />
                </div>
                <div className="space-y-1">
                  <p className="text-[10px] font-black text-neutral-400 uppercase tracking-widest">Lifetime Earnings</p>
                  <p className="text-xl font-bold text-neutral-800">KES {house.totalEarnings.toLocaleString()}</p>
                </div>
              </div>

