                <p className="text-[10px] font-black text-neutral-400 uppercase tracking-widest flex items-center gap-2"><RefreshCw size={14}/> Modify Occupancy Status</p>
                <div className="flex gap-2">
                  <UnitStatusBtn 
                    active={(pendingStatus || house.status) === HouseStatus.RENTED} 
                    onClick={() => setPendingStatus(HouseStatus.RENTED)} 
                    color="green" 
                    label="Rented" 
                    icon={<CheckCircle2 size={18}/>} 
                  />
                  <UnitStatusBtn 
                    active={(pendingStatus || house.status) === HouseStatus.VACANT} 
                    onClick={() => setPendingStatus(HouseStatus.VACANT)} 
                    color="amber" 
                    label="Vacant" 
                    icon={<CircleDashed size={18}/>} 
                  />
                  <UnitStatusBtn 
                    active={(pendingStatus || house.status) === HouseStatus.UNDER_REPAIR} 
                    onClick={() => setPendingStatus(HouseStatus.UNDER_REPAIR)} 
                    color="red" 
                    label="Repair" 
                    icon={<Hammer size={18}/>} 
                  />
                </div>

                {pendingStatus && pendingStatus !== house.status && (
                  <div className="animate-slideUp bg-royal-500 p-1.5 rounded-2xl flex items-center justify-between pl-6 shadow-xl shadow-royal-500/20">
                    <span className="text-white text-[10px] font-black uppercase tracking-widest">Pending: {pendingStatus.replace('_', ' ')}</span>
                    <button 
                      onClick={handleStatusCommit}
                      className="bg-white text-royal-500 px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-royal-50 active:scale-95 transition-all shadow-lg"
