                          <span className="text-[10px] text-neutral-300 italic font-medium">No records</span>
                        )}
                      </td>
                      <td className="px-8 py-6"><BillStatusBadge status={t.bills.status} /></td>
                      <td className="px-8 py-6 text-right">
                        <div className="flex justify-end gap-3">
                          <button onClick={() => setSelectedTenant(t)} className="p-2.5 bg-neutral-100 hover:bg-neutral-200 text-neutral-500 rounded-xl transition-all"><Eye size={16} /></button>
                          <button onClick={() => handleEditClick(t)} className="p-2.5 bg-neutral-100 hover:bg-royal-50 text-neutral-500 hover:text-royal-500 rounded-xl transition-all"><Edit3 size={16} /></button>
                          <button onClick={() => handleSendReminder(t)} disabled={loadingAI === t.id} className="inline-flex items-center gap-2 bg-royal-500 hover:bg-royal-600 text-white px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-royal-500/20 disabled:opacity-50 active:scale-95 transition-all">
                            {loadingAI === t.id ? <Activity className="animate-spin" size={14}/> : <Send size={14}/>} Notify
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'billing' && (
        <div className="space-y-10">
          <button 
            onClick={() => setShowLogPaymentModal(true)}
            className="fixed bottom-10 right-10 w-16 h-16 bg-royal-500 text-white rounded-full shadow-2xl flex items-center justify-center hover:bg-royal-600 hover:scale-110 active:scale-95 transition-all z-50 border-4 border-white group"
            title="Log Manual Payment"
          >
            <Plus size={32} className="group-hover:rotate-90 transition-transform duration-300" />
          </button>

          <div className="bg-white rounded-[3rem] border border-neutral-200 shadow-xl overflow-hidden animate-slideUp">
            <div className="bg-neutral-900 p-10 text-white flex flex-col md:flex-row justify-between items-start md:items-center gap-6 relative overflow-hidden">
               <div className="absolute top-0 right-0 p-10 opacity-5 text-royal-500"><Droplets size={200} /></div>
               <div className="relative z-10">
                  <div className="flex items-center gap-3 mb-2">
                     <span className="bg-royal-500 text-white text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-full shadow-lg shadow-royal-500/20">Monthly Billing Cycle</span>
                     <span className="text-neutral-400 text-xs font-bold uppercase">Rate: 150/unit</span>
                  </div>
                  <h3 className="text-4xl font-royal font-black tracking-tight">Utility Metering Workstation</h3>
                  <p className="text-neutral-500 text-sm mt-1">Audit and record consumption across all {tenants.length} active units</p>
               </div>

               <div className="flex items-center gap-4 relative z-10">
                  <div className="relative">
                    <Search size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-neutral-500" />
                    <input 
                      type="text" 
                      placeholder="Find Unit..." 
                      value={searchQuery}
                      onChange={e => setSearchQuery(e.target.value)}
                      className="bg-white/5 border border-white/10 pl-12 pr-6 py-4 rounded-2xl text-sm font-bold focus:bg-white/10 transition-all outline-none w-64" 
                    />
                  </div>
                  {Object.keys(pendingReadings).length > 0 && (
                    <button 
                      onClick={handleCommitAllReadings}
                      className="bg-royal-500 hover:bg-royal-600 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3 shadow-2xl shadow-royal-500/20 animate-pulse"
                    >
                      <Zap size={18} /> Commit {Object.keys(pendingReadings).length} Readings
                    </button>
                  )}
               </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-neutral-50 border-b border-neutral-100">
                  <tr>
                    <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Suite / Resident</th>
                    <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Previous Record</th>
                    <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest">New Meter Entry</th>
                    <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Net Consumption</th>
                    <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest text-right">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-neutral-50">
                  {meteringTenants.map(t => {
                    const pendingValue = pendingReadings[t.id];
                    const displayReading = pendingValue !== undefined ? pendingValue : t.bills.currWaterReading;
                    const isPending = pendingValue !== undefined;
                    const units = Math.max(0, displayReading - t.bills.currWaterReading);
                    const cost = units * 150;
                    const isSuccess = updatedTenantIds.has(t.id);

                    return (
                      <tr key={t.id} className={`transition-all hover:bg-neutral-50/50 group ${isPending ? 'bg-royal-50/30' : ''}`}>
                        <td className="px-10 py-8">
                           <div className="flex items-center gap-4">
                              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-royal font-black text-lg transition-all ${isPending ? 'bg-royal-500 text-white shadow-lg' : 'bg-neutral-100 text-neutral-400 group-hover:bg-neutral-200'}`}>
                                 {t.houseNumber}
                              </div>
                              <div>
                                 <div className="font-bold text-neutral-900 group-hover:text-royal-500 transition-colors">{t.name}</div>
                                 <div className="text-[10px] text-neutral-400 font-black uppercase tracking-widest">Unit {t.houseNumber}</div>
                              </div>
                           </div>
                        </td>
                        <td className="px-10 py-8">
                           <div className="bg-neutral-100 px-4 py-2 rounded-xl inline-block">
                              <span className="text-neutral-500 text-xs font-mono font-bold">{t.bills.currWaterReading}</span>
                              <span className="text-[8px] font-black text-neutral-400 uppercase ml-2">Units</span>
                           </div>
                        </td>
                        <td className="px-10 py-8">
                           <div className="relative w-40">
                             <input 
                                type="number" 
                                className={`w-full bg-white border-2 p-4 rounded-2xl text-center font-black text-lg outline-none transition-all ${isSuccess ? 'border-green-500 bg-green-50' : isPending ? 'border-royal-500 ring-4 ring-royal-500/5' : 'border-neutral-200 hover:border-neutral-300'}`}
                                value={displayReading}
                                min={t.bills.currWaterReading}
                                onChange={(e) => setPendingReadings(prev => ({ ...prev, [t.id]: Number(e.target.value) }))}
                             />
                             {isPending && (
                               <button 
                                 type="button"
                                 onClick={() => handleApplyUpdate(t.id)}
                                 className="absolute -right-12 top-1/2 -translate-y-1/2 p-3 bg-royal-500 text-white rounded-xl shadow-lg hover:scale-110 active:scale-90 transition-all"
                               >
                                 <Save size={16}/>
                               </button>
                             )}
                           </div>
                        </td>
                        <td className="px-10 py-8">
                           {units > 0 ? (
                             <div className="animate-fadeIn">
                                <div className="flex items-center gap-1.5 text-cyan-600 font-bold text-sm">
                                   <ArrowUp size={14}/> {units} Units
                                </div>
                                <div className="text-[10px] font-black text-neutral-900 uppercase">KES {cost.toLocaleString()}</div>
                             </div>
                           ) : (
                             <span className="text-[10px] text-neutral-300 font-bold uppercase italic">No change</span>
                           )}
                        </td>
                        <td className="px-10 py-8 text-right">
                           {isSuccess ? (
                             <div className="inline-flex items-center gap-2 bg-green-100 text-green-700 px-4 py-2 rounded-full font-black text-[10px] uppercase border border-green-200 animate-bounce">
                                <Check size={14}/> Logged
                             </div>
                           ) : isPending ? (
                             <div className="inline-flex items-center gap-2 bg-royal-100 text-royal-700 px-4 py-2 rounded-full font-black text-[10px] uppercase border border-royal-200">
                                <Activity size={14} className="animate-pulse"/> Pending
                             </div>
                           ) : (
                             <div className="text-[10px] font-black text-neutral-300 uppercase italic">Awaiting Cycle</div>
                           )}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
            <div className="bg-white p-10 rounded-[3rem] border border-neutral-200 shadow-sm overflow-hidden">
              <div className="flex justify-between items-center mb-8">
                 <h3 className="text-xl font-bold flex items-center gap-3"><History className="text-royal-500" /> Latest Collections</h3>
                 <button onClick={() => setActiveTab('tenants')} className="text-royal-500 text-[10px] font-black uppercase tracking-widest hover:underline">Full Registry &rarr;</button>
              </div>
              <div className="space-y-4 max-h-[400px] overflow-y-auto scrollbar-hide">
                {filteredCollections.slice(0, 10).map(p => {
                    const tenant = tenants.find(t => t.id === p.tenantId);
                    return (
                      <div key={p.id} className="flex items-center justify-between p-5 bg-neutral-50 rounded-2xl border border-neutral-100 hover:border-royal-200 transition-all">
