    if (!leaseData.signed) {
      alert("Tenant signature required for digital lease agreement.");
      return;
    }

    const newTenant: Tenant = {
      id: `t-${Date.now()}`,
      name: tenantData.name,
      email: tenantData.email,
      houseNumber: tenantData.houseNumber,
      idNumber: tenantData.idNumber,
      phoneNumber: tenantData.phoneNumber,
      nextOfKin: tenantData.nextOfKin,
      joinDate: leaseData.startDate,
      agreementUrl: `royal-lease-${tenantData.houseNumber}-${Date.now()}.pdf`,
      bills: { 
        rent: tenantData.rent, 
        water: 0, 
        prevWaterReading: 0,
        currWaterReading: 0,
        garbage: 500, 
        total: tenantData.rent + 500, 
        status: 'UNPAID' 
      },
      lease: {
        startDate: leaseData.startDate,
        endDate: leaseData.endDate,
        depositAmount: tenantData.rent,
        depositStatus: 'HELD',
        status: 'ACTIVE'
      },
      meterReadings: []
    };
    onSubmit(newTenant);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-neutral-900/90 backdrop-blur-sm animate-fadeIn">
      <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-slideUp border border-neutral-200">
        <div className="bg-royal-500 p-8 text-white flex justify-between items-center relative overflow-hidden">
          <div className="absolute top-0 right-0 p-6 opacity-10"><FilePenLine size={120}/></div>
          <div className="relative z-10">
             <div className="flex items-center gap-2 mb-1">
               <span className={`px-2 py-0.5 rounded-md text-[8px] font-black uppercase ${step === 1 ? 'bg-white text-royal-500' : 'bg-royal-400 text-white'}`}>Step 1</span>
               <span className={`px-2 py-0.5 rounded-md text-[8px] font-black uppercase ${step === 2 ? 'bg-white text-royal-500' : 'bg-royal-400 text-white'}`}>Step 2</span>
             </div>
             <h3 className="text-2xl font-royal font-black tracking-tight">{step === 1 ? 'Tenant Intelligence Profiling' : 'E-Contracting Sequence'}</h3>
             <p className="text-royal-100 text-[10px] font-black uppercase tracking-widest">Resident Lifecycle Management</p>
          </div>
          <button type="button" onClick={onClose} className="relative z-20 p-3 bg-white/10 hover:bg-white/20 rounded-2xl transition-all"><X size={20} /></button>
        </div>

        {step === 1 ? (
          <form onSubmit={handleNext} className="p-10 grid grid-cols-1 md:grid-cols-2 gap-6">
            <InputGroup icon={<User size={14}/>} label="Full Legal Name" placeholder="e.g. David Mutua" value={tenantData.name} onChange={(v) => setTenantData({...tenantData, name: v})} />
            <InputGroup icon={<Hash size={14}/>} label="National ID / Passport" placeholder="e.g. 12345678" value={tenantData.idNumber} onChange={(v) => setTenantData({...tenantData, idNumber: v})} />
            <InputGroup icon={<Phone size={14}/>} label="Phone Number" placeholder="e.g. 0712..." value={tenantData.phoneNumber} onChange={(v) => setTenantData({...tenantData, phoneNumber: v})} />
            <InputGroup icon={<Mail size={14}/>} label="Email Address" placeholder="tenant@example.com" value={tenantData.email} onChange={(v) => setTenantData({...tenantData, email: v})} />
            <InputGroup icon={<Users size={14}/>} label="Emergency Contact (NOK)" placeholder="Name & Number" value={tenantData.nextOfKin} onChange={(v) => setTenantData({...tenantData, nextOfKin: v})} />

