                <span className="text-[10px] font-black uppercase tracking-widest text-neutral-400">Monthly Commitment</span>
                <div className="flex items-end justify-between mt-4">
                  <div className="text-2xl font-bold text-neutral-800 tracking-tighter">KES {(tenant.bills.rent + tenant.bills.garbage).toLocaleString()}</div>
                  <span className="text-[9px] font-black text-royal-500 uppercase">Fixed Costs</span>
                </div>
              </div>
            </div>

            <div className="bg-white p-10 rounded-[3rem] border border-neutral-200 shadow-sm overflow-hidden">
