               </div>

               <div className="bg-neutral-50 p-6 rounded-[2rem] border border-neutral-100 mb-8 grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-neutral-400 uppercase tracking-widest pl-1">Category & Method</label>
                    <div className="flex gap-2">
                      <select value={filterType} onChange={(e) => setFilterType(e.target.value)} className="flex-1 bg-white border border-neutral-200 rounded-xl px-3 py-2.5 text-[10px] font-bold outline-none shadow-sm">
                        <option value="ALL">All Categories</option>
                        <option value="RENT">House Rent</option>
                        <option value="WATER">Water Bill</option>
                        <option value="GARBAGE">Service Fee</option>
                      </select>
                      <select value={filterMethod} onChange={(e) => setFilterMethod(e.target.value)} className="flex-1 bg-white border border-neutral-200 rounded-xl px-3 py-2.5 text-[10px] font-bold outline-none shadow-sm">
                        <option value="ALL">All Methods</option>
                        <option value="M-Pesa">M-Pesa</option>
                        <option value="Bank">Bank</option>
                      </select>
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-neutral-400 uppercase tracking-widest pl-1">Timeline</label>
