                          <div className="font-black text-neutral-900">KES {p.amount.toLocaleString()}</div>
                          <div className="text-[8px] text-neutral-400 font-mono uppercase">{p.reference}</div>
                        </div>
                      </div>
                    );
                  })}
              </div>
            </div>

            <div className="bg-neutral-900 text-white p-10 rounded-[3rem] shadow-2xl relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-10 opacity-0 group-hover:opacity-10 transition-opacity duration-700 text-royal-500"><Wrench size={160} /></div>
              <h3 className="text-xl font-bold mb-8 flex items-center gap-3 font-royal text-royal-100"><RefreshCw className="text-royal-500" /> Maintenance Logs</h3>
