                                className={`w-full bg-white border-2 p-4 rounded-2xl text-center font-black text-lg outline-none transition-all ${isSuccess ? 'border-green-500 bg-green-50' : isInvalid ? 'border-red-500 ring-4 ring-red-500/10' : isPending ? 'border-royal-500 ring-4 ring-royal-500/5' : 'border-neutral-200 hover:border-neutral-300'}`}
                                value={displayReading}
                                onChange={(e) => setPendingReadings(prev => ({ ...prev, [t.id]: Number(e.target.value) }))}
                             />
                             {isInvalid && (
                               <div className="absolute top-full left-0 mt-2 text-[8px] font-black text-red-500 uppercase tracking-widest whitespace-nowrap animate-fadeIn flex items-center gap-1">
