  <div className="space-y-2">
    <label className="text-[10px] font-black text-neutral-400 uppercase tracking-widest flex items-center gap-2">{icon} {label}</label>
    <input 
      type={type} 
      required 
      placeholder={placeholder} 
      className="w-full bg-neutral-50 border-2 border-neutral-100 p-4 rounded-2xl focus:border-royal-500 outline-none transition-all text-sm font-bold text-neutral-700" 
