                    type="button"
                    onClick={() => setActiveViewTab('maintenance')}
                    className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${activeViewTab === 'maintenance' ? 'bg-white text-royal-500 shadow-sm' : 'text-neutral-400 hover:text-neutral-600'}`}
                   >
                     Maintenance
                   </button>
                   <button 
                    type="button"
                    onClick={() => setActiveViewTab('utility')}
                    disabled={!currentTenant}
                    className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${activeViewTab === 'utility' ? 'bg-white text-royal-500 shadow-sm' : 'text-neutral-400 hover:text-neutral-600'} disabled:opacity-30`}
                   >
                     Utility Audit
                   </button>
                </div>

                {activeViewTab === 'maintenance' && (
                  <div className="space-y-2 animate-fadeIn">
                    {house.repairs.length > 0 ? (
                      house.repairs.map(r => (
                        <div key={r.id} className="flex justify-between items-center p-4 bg-neutral-50 rounded-xl border border-neutral-100">
                          <div>
                            <p className="text-sm font-bold text-neutral-800">{r.description}</p>
                            <p className="text-[10px] text-neutral-400 font-medium">{r.date} • {r.category}</p>
