                      ))
                    ) : (
                      <p className="text-xs text-neutral-400 italic">No maintenance records for this unit.</p>
                    )}
                  </div>
                )}

                {activeViewTab === 'utility' && currentTenant && (
                  <div className="space-y-3 animate-fadeIn">
                    {(currentTenant.meterReadings || []).length > 0 ? (
