export enum UserRole {
  TENANT = 'TENANT',
  CARETAKER = 'CARETAKER',
  LANDLORD = 'LANDLORD'
}

export enum HouseStatus {
  VACANT = 'VACANT',
  RENTED = 'RENTED',
  UNDER_REPAIR = 'UNDER_REPAIR'
}

export interface MeterReading {
  id: string;
  date: string;
  reading: number;
  unitsConsumed: number;
  cost: number;
}

export interface Bill {
  rent: number;
  water: number;
  prevWaterReading: number;
  currWaterReading: number;
  garbage: number;
  total: number;
  status: 'PAID' | 'UNPAID' | 'PARTIAL';
}

export interface RentAgreement {
  startDate: string;
  depositAmount: number;
  depositStatus: 'HELD' | 'REFUNDED' | 'FORFEITED';
  status: 'ACTIVE' | 'TERMINATED';
  tenantSignature?: string;
  landlordSignature?: string;
  witnessSignature?: string;
  signedDate?: string;
}

export interface Incident {
  id: string;
  date: string;
  type: 'LEASE_RENEWAL' | 'LATE_PAYMENT' | 'MAINTENANCE_ISSUE' | 'COMPLIANCE' | 'NOTE';
  description: string;
  severity: 'low' | 'medium' | 'high';
}

export interface Tenant {
  id: string;
  name: string;
  email: string;
  houseNumber: string;
  idNumber: string;
  phoneNumber: string;
  nextOfKin: string;
  agreementUrl?: string;
  bills: Bill;
  joinDate: string;
  rentAgreement?: RentAgreement;
  incidents?: Incident[];
  meterReadings?: MeterReading[];
}

export interface PastTenant {
  name: string;
  period: string;
  exitReason: string;
}

export interface House {
  id: string;
  houseNumber: string;
  type: 'Studio' | '1 Bedroom' | '2 Bedroom' | 'Penthouse';
  status: HouseStatus;
  lastVacantDate: string;
  repairs: Repair[];
  totalEarnings: number;
  tenantHistory: PastTenant[];
}

export interface Repair {
  id: string;
  date: string;
  description: string;
  cost: number;
  category: string;
}

export interface Expense {
  id: string;
  date: string;
  category: 'MAINTENANCE' | 'UTILITIES' | 'TAX' | 'LEGAL' | 'SALARY' | 'OTHER';
  amount: number;
  description: string;
  propertyId?: string;
  unitId?: string;
}

export interface PaymentRecord {
  id: string;
  tenantId: string;
  amount: number;
  date: string;
  type: 'RENT' | 'WATER' | 'GARBAGE' | 'TOTAL';
  reference: string;
  method: string;
}

export interface Owner {
  id: string;
  name: string;
  balance: number;
  managementFeeRate: number;
}

import React, { useState, useRef } from 'react';
import { Tenant, House, PaymentRecord, Expense, HouseStatus } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid } from 'recharts';
import { 
  TrendingUp, Users, DollarSign, Home, Clock, CheckCircle2, 
  AlertTriangle, Activity, X, User, Eye, FileText, 
  Download, Briefcase, Wallet, Plus, Trash2, Filter, Printer, ShieldCheck, Signature, ArrowRight
} from 'lucide-react';
import { analyzeTenantFinancials, analyzePropertyHealth } from '../services/geminiService';

interface Props {
  tenants: Tenant[];
  houses: House[];
  payments: PaymentRecord[];
  expenses: Expense[];
  view: string;
  onAddExpense: (expense: Expense) => void;
  onUpdateTenant?: (t: Tenant) => void;
}

export const LandlordDashboard: React.FC<Props> = ({ tenants, houses, payments, expenses, view, onAddExpense, onUpdateTenant }) => {
  const [selectedTenant, setSelectedTenant] = useState<Tenant | null>(null);
  const [showExpenseModal, setShowExpenseModal] = useState(false);
  const [showReportModal, setShowReportModal] = useState<'FINANCIAL' | 'OCCUPANCY' | 'ARREARS' | null>(null);
  const [loadingAI, setLoadingAI] = useState(false);
  const [aiReport, setAiReport] = useState<string | null>(null);

  // Stats calculations
  const totalExpected = tenants.reduce((acc, t) => acc + t.bills.rent, 0);
  const totalCollected = payments.reduce((acc, p) => acc + p.amount, 0);
  const totalExpenses = expenses.reduce((acc, e) => acc + e.amount, 0);
  const maintenanceExpenses = houses.reduce((acc, h) => acc + h.repairs.reduce((rAcc, r) => rAcc + r.cost, 0), 0);
  const occupancyRate = houses.length > 0 ? (houses.filter(h => h.status === HouseStatus.RENTED).length / houses.length) * 100 : 0;
  const netIncome = totalCollected - totalExpenses - maintenanceExpenses;

  const COLORS = ['#1F6AE1', '#22C55E', '#F59E0B', '#EF4444'];

  const occupancyData = [
    { name: 'Occupied', value: houses.filter(h => h.status === HouseStatus.RENTED).length },
    { name: 'Vacant', value: houses.filter(h => h.status === HouseStatus.VACANT).length },
    { name: 'Repair', value: houses.filter(h => h.status === HouseStatus.UNDER_REPAIR).length },
  ];

  const financialData = [
    { name: 'Gross Income', amount: totalCollected },
    { name: 'Maintenance', amount: maintenanceExpenses },
    { name: 'Operating Exp', amount: totalExpenses },
    { name: 'Net Income', amount: netIncome },
  ];

  const handleAIReport = async () => {
    setLoadingAI(true);
    try {
      const result = await analyzePropertyHealth(houses, [...expenses, ...houses.flatMap(h => h.repairs)]);
      setAiReport(result);
    } catch (e) { console.error(e); }
    finally { setLoadingAI(false); }
  };

  const handleCounterSign = (tenant: Tenant) => {
    if (onUpdateTenant) {
      const updated = {
        ...tenant,
        rentAgreement: {
          ...tenant.rentAgreement!,
          landlordSignature: 'SIGNED_BY_OWNER',
          signedDate: new Date().toISOString()
        }
      };
      onUpdateTenant(updated);
      alert(`Agreement for Unit ${tenant.houseNumber} has been officially counter-signed.`);
    }
  };

  if (view === 'expenses') {
    return (
      <div className="space-y-8 animate-fadeIn">
        <div className="flex justify-between items-center">
          <div>
            <h2 className="text-3xl font-royal font-bold text-neutral-900">Expense Ledger</h2>
            <p className="text-neutral-400 text-sm">Monitor operational costs and maintenance outlay</p>
          </div>
          <button onClick={() => setShowExpenseModal(true)} className="flex items-center gap-2 bg-royal-500 text-white px-6 py-3 rounded-2xl font-bold hover:bg-royal-600 shadow-xl shadow-royal-500/20">
            <Plus size={20}/> Log New Expense
          </button>
        </div>

        {showExpenseModal && <AddExpenseModal onAdd={onAddExpense} onClose={() => setShowExpenseModal(false)} />}

        <div className="bg-white rounded-[2.5rem] border border-neutral-200 shadow-sm overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-neutral-50 border-b">
              <tr>
                <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Date</th>
                <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Category</th>
                <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Description</th>
                <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest text-right">Amount</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-neutral-50">
              {expenses.length === 0 && (
                <tr><td colSpan={4} className="p-20 text-center text-neutral-300 italic">No operational expenses logged yet.</td></tr>
              )}
              {expenses.map(e => (
                <tr key={e.id} className="hover:bg-neutral-50 transition-colors">
                  <td className="px-8 py-6 text-sm text-neutral-600 font-medium">{new Date(e.date).toLocaleDateString()}</td>
                  <td className="px-8 py-6">
                    <span className="bg-neutral-100 text-neutral-600 px-3 py-1 rounded-lg text-[10px] font-black uppercase border border-neutral-200">{e.category}</span>
                  </td>
                  <td className="px-8 py-6 text-sm font-bold text-neutral-800">{e.description}</td>
                  <td className="px-8 py-6 text-right font-black text-red-500">KES {e.amount.toLocaleString()}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    );
  }

  if (view === 'reports') {
    return (
      <div className="space-y-8 animate-fadeIn">
        {showReportModal && (
          <ReportPreviewModal 
            type={showReportModal} 
            data={{ tenants, houses, payments, expenses, stats: { totalExpected, totalCollected, totalExpenses, netIncome } }} 
            onClose={() => setShowReportModal(null)} 
          />
        )}

        <div className="flex justify-between items-center">
          <div>
            <h2 className="text-3xl font-royal font-bold text-neutral-900">Intelligence & Export</h2>
            <p className="text-neutral-400 text-sm">Official documentation and performance audit</p>
          </div>
          <button onClick={handleAIReport} disabled={loadingAI} className="flex items-center gap-2 bg-royal-900 text-white px-6 py-3 rounded-2xl font-bold hover:bg-neutral-800 shadow-xl active:scale-95 transition-all">
            {loadingAI ? <Activity className="animate-spin" size={18}/> : <Briefcase size={18}/>}
            {loadingAI ? 'Analyzing...' : 'Generate AI Executive Audit'}
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
           <ReportActionCard title="Financial Statement" desc="Revenue, Expenses & P&L" icon={<DollarSign/>} onClick={() => setShowReportModal('FINANCIAL')} />
           <ReportActionCard title="Occupancy Audit" desc="Unit Status & History" icon={<Home/>} onClick={() => setShowReportModal('OCCUPANCY')} />
           <ReportActionCard title="Arrears Aging" desc="Defaulter Risk Profile" icon={<AlertTriangle/>} onClick={() => setShowReportModal('ARREARS')} />
        </div>

        {aiReport && (
          <div className="bg-royal-50 border border-royal-100 p-8 rounded-[2.5rem] relative overflow-hidden shadow-sm animate-slideUp">
             <div className="absolute top-0 right-0 p-10 opacity-5 text-royal-500"><FileText size={160} /></div>
             <div className="flex items-center gap-3 mb-4">
                <span className="bg-royal-500 text-white text-[10px] font-black uppercase tracking-widest px-2.5 py-1 rounded-lg">AI Financial Insight</span>
             </div>
             <p className="text-xl font-royal text-neutral-800 italic leading-relaxed relative z-10">"{aiReport}"</p>
          </div>
        )}

        <div className="bg-white p-10 rounded-[2.5rem] border border-neutral-200 shadow-sm">
           <h3 className="text-xl font-bold mb-8 flex items-center gap-3"><Signature className="text-royal-500" /> Pending Counter-Signatures</h3>
           <div className="space-y-4">
              {tenants.filter(t => t.rentAgreement?.tenantSignature && !t.rentAgreement.landlordSignature).map(t => (
                <div key={t.id} className="flex items-center justify-between p-6 bg-neutral-50 rounded-2xl border border-neutral-100 group hover:border-royal-200 transition-all">
                   <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-royal-500 shadow-sm group-hover:scale-110 transition-transform"><FileText size={24}/></div>
                      <div>
                         <h4 className="font-bold text-neutral-800">Unit {t.houseNumber} - {t.name}</h4>
                         <p className="text-[10px] text-neutral-400 font-black uppercase tracking-widest">Signed by Tenant on {t.joinDate}</p>
                      </div>
                   </div>
                   <button onClick={() => handleCounterSign(t)} className="flex items-center gap-2 bg-royal-500 text-white px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-royal-600 transition-all shadow-lg shadow-royal-500/20">
                      Execute Signature <ShieldCheck size={14}/>
                   </button>
                </div>
              ))}
              {tenants.filter(t => t.rentAgreement?.tenantSignature && !t.rentAgreement.landlordSignature).length === 0 && (
                <div className="py-12 text-center text-neutral-300 italic text-sm">All legal agreements are fully executed.</div>
              )}
           </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-fadeIn">
      {selectedTenant && <TenantIntelligenceModal tenant={selectedTenant} payments={payments.filter(p => p.tenantId === selectedTenant.id)} onClose={() => setSelectedTenant(null)} />}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Collected Rent" value={`KES ${totalCollected.toLocaleString()}`} icon={<Wallet className="text-royal-500" />} trend="up" change="+8.4%" />
        <StatCard title="Total Arrears" value={`KES ${(totalExpected - totalCollected).toLocaleString()}`} icon={<AlertTriangle className="text-red-500" />} trend="down" change="-2.1%" />
        <StatCard title="Portfolio Yield" value={`${occupancyRate.toFixed(1)}%`} icon={<TrendingUp className="text-green-500" />} change="On Target" />
        <StatCard title="Active Units" value={`${houses.length}`} icon={<Home className="text-amber-500" />} change="100% Verified" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-10 rounded-[2.5rem] border border-neutral-200 shadow-sm">
          <h3 className="text-lg font-bold mb-10 text-neutral-800">Financial Growth Pattern</h3>
          <div className="h-[350px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={financialData} barSize={60}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#F1F5F9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 11, fill: '#94A3B8', fontWeight: 600}} />
                <YAxis hide />
                <Tooltip cursor={{fill: '#F8FAFC'}} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)' }} />
                <Bar dataKey="amount" radius={[12, 12, 0, 0]}>
                  {financialData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-neutral-900 p-10 rounded-[2.5rem] text-white flex flex-col justify-between shadow-2xl">
           <div>
             <h3 className="text-lg font-bold mb-8">Occupancy Distribution</h3>
             <div className="h-[220px] w-full flex items-center justify-center">
               <ResponsiveContainer width="100%" height="100%">
                 <PieChart>
                   <Pie data={occupancyData} cx="50%" cy="50%" innerRadius={70} outerRadius={90} paddingAngle={8} dataKey="value">
                     {occupancyData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} stroke="rgba(0,0,0,0)" />)}
                   </Pie>
                   <Tooltip />
                 </PieChart>
               </ResponsiveContainer>
             </div>
             <div className="space-y-4 mt-8">
               {occupancyData.map((item, idx) => (
                 <div key={item.name} className="flex items-center justify-between">
                   <div className="flex items-center gap-2">
                     <div className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[idx] }} />
                     <span className="text-xs text-neutral-400 font-medium">{item.name}</span>
                   </div>
                   <span className="text-sm font-bold">{item.value} Units</span>
                 </div>
               ))}
             </div>
           </div>
        </div>
      </div>
    </div>
  );
};

// Internal components
const ReportActionCard: React.FC<{ title: string, desc: string, icon: React.ReactNode, onClick: () => void }> = ({ title, desc, icon, onClick }) => (
  <button onClick={onClick} className="bg-white p-8 rounded-[2rem] border border-neutral-200 shadow-sm text-left group hover:border-royal-500 transition-all hover:-translate-y-1">
     <div className="p-4 bg-neutral-50 rounded-2xl text-neutral-400 group-hover:bg-royal-50 group-hover:text-royal-500 w-fit mb-6 transition-colors">{icon}</div>
     <h4 className="text-lg font-bold text-neutral-800">{title}</h4>
     <p className="text-xs text-neutral-400 font-medium mt-1 mb-6">{desc}</p>
     <div className="flex items-center gap-2 text-[10px] font-black uppercase text-royal-500 tracking-widest">
        Generate Report <Printer size={12}/>
     </div>
  </button>
);

const ReportPreviewModal: React.FC<{ type: string, data: any, onClose: () => void }> = ({ type, data, onClose }) => {
  const printRef = useRef<HTMLDivElement>(null);
  const handlePrint = () => {
    const printContent = printRef.current?.innerHTML;
    const printWindow = window.open('', '', 'height=1000,width=800');
    if (printWindow) {
      printWindow.document.write(`
        <html>
          <head>
            <title>Royal Flats - Official Report</title>
            <script src="https://cdn.tailwindcss.com"></script>
            <style>
              @media print {
                .no-print { display: none; }
                body { padding: 40px; font-family: 'Times New Roman', serif; }
              }
              body { padding: 40px; }
            </style>
          </head>
          <body>
            ${printContent}
            <script>window.print(); setTimeout(() => window.close(), 100);</script>
          </body>
        </html>
      `);
      printWindow.document.close();
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-neutral-900/95 backdrop-blur-md animate-fadeIn">
      <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl flex flex-col h-[90vh] overflow-hidden animate-slideUp">
        <div className="p-8 bg-neutral-50 border-b flex justify-between items-center">
           <div>
              <h3 className="text-xl font-bold">Report Preview</h3>
              <p className="text-xs text-neutral-400">Review generated document before export</p>
           </div>
           <div className="flex gap-4">
              <button onClick={onClose} className="p-3 bg-neutral-200 hover:bg-neutral-300 rounded-xl transition-all"><X size={20}/></button>
              <button onClick={handlePrint} className="flex items-center gap-2 bg-royal-500 text-white px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-royal-500/20">
                 Export as PDF <Printer size={16}/>
              </button>
           </div>
        </div>

        <div className="flex-1 overflow-y-auto p-20 bg-neutral-100">
           <div ref={printRef} className="bg-white p-12 shadow-sm min-h-[1000px] border border-neutral-200 mx-auto max-w-[800px] text-neutral-900">
              {/* Report Header */}
              <div className="flex justify-between items-start border-b-4 border-neutral-900 pb-8 mb-12">
                 <div>
                    <h1 className="text-4xl font-serif font-black tracking-tight uppercase">Royal Flats</h1>
                    <p className="text-xs font-black uppercase tracking-[0.3em] mt-1 text-neutral-500">Official Management Report</p>
                 </div>
                 <div className="text-right text-xs">
                    <p className="font-bold">Generation Date: {new Date().toLocaleDateString()}</p>
                    <p>Report Ref: RF-2024-{(Math.random() * 10000).toFixed(0)}</p>
                 </div>
              </div>

              <div className="mb-12">
                 <h2 className="text-2xl font-bold uppercase border-b-2 border-neutral-100 pb-2 mb-6">{type.replace('_', ' ')} Audit</h2>

                 {type === 'FINANCIAL' && (
                    <div className="space-y-10">
                       <div className="grid grid-cols-2 gap-8">
                          <div className="p-6 bg-neutral-50 rounded-lg">
                             <p className="text-[10px] font-black uppercase text-neutral-400 mb-2">Total Collections</p>
                             <p className="text-2xl font-bold">KES {data.stats.totalCollected.toLocaleString()}</p>
                          </div>
                          <div className="p-6 bg-neutral-50 rounded-lg">
                             <p className="text-[10px] font-black uppercase text-neutral-400 mb-2">Net Income</p>
                             <p className="text-2xl font-bold">KES {data.stats.netIncome.toLocaleString()}</p>
                          </div>
                       </div>
                       <table className="w-full text-left text-sm">
                          <thead>
                             <tr className="bg-neutral-900 text-white"><th className="p-4">Transaction Date</th><th className="p-4">Description</th><th className="p-4 text-right">Amount</th></tr>
                          </thead>
                          <tbody className="divide-y border-b">
                             {data.payments.slice(0, 15).map((p: any) => (
                                <tr key={p.id}><td className="p-4">{new Date(p.date).toLocaleDateString()}</td><td className="p-4">{p.type} - {p.reference}</td><td className="p-4 text-right">KES {p.amount.toLocaleString()}</td></tr>
                             ))}
                          </tbody>
                       </table>
                    </div>
                 )}

                 {type === 'OCCUPANCY' && (
                    <div className="space-y-8">
                       <div className="grid grid-cols-3 gap-6">
                          <div className="text-center">
                             <p className="text-3xl font-bold">{data.houses.length}</p>
                             <p className="text-[10px] font-black uppercase text-neutral-400">Total Suites</p>
                          </div>
                          <div className="text-center">
                             <p className="text-3xl font-bold">{data.tenants.length}</p>
                             <p className="text-[10px] font-black uppercase text-neutral-400">Active Residents</p>
                          </div>
