    e.preventDefault();
    onAdd({
      id: `exp-${Date.now()}`,
      date: new Date().toISOString(),
      category: data.category as any,
      amount: Number(data.amount),
      description: data.description
    });
    onClose();
  };
  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-neutral-900/95 backdrop-blur-md animate-fadeIn">
      <div className="bg-white w-full max-w-xl rounded-[4rem] shadow-2xl overflow-hidden animate-slideUp">
