              <label className="text-[10px] font-black uppercase text-neutral-500 tracking-widest pl-1">Expense Classification</label>
              <select className="w-full p-5 bg-neutral-50 border-2 border-neutral-100 rounded-3xl outline-none focus:border-royal-500 font-black text-lg transition-all appearance-none" value={data.category} onChange={e => setData({...data, category: e.target.value})}>
                 <option value="MAINTENANCE">Maintenance & Repairs</option>
                 <option value="UTILITIES">Utility Provisions</option>
                 <option value="TAX">Statutory Taxes</option>
                 <option value="LEGAL">Legal & Compliance</option>
                 <option value="SALARY">Staff Salaries</option>
                 <option value="OTHER">Sundry / Miscellaneous</option>
              </select>
