          <button onClick={() => setShowExpenseModal(true)} className="bg-royal-500 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3 shadow-2xl shadow-royal-500/20 hover:bg-royal-600 active:scale-95 transition-all">
            <Plus size={18}/> Log New Outflow
