        </div>

        {showExpenseModal && <AddExpenseModal onAdd={onAddExpense} onClose={() => setShowExpenseModal(false)} />}

        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
           {expenseByCategory.map((cat, i) => (
             <div key={cat.name} className="bg-white p-6 rounded-3xl border border-neutral-100 shadow-sm">
                <p className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-1">{cat.name}</p>
                <p className="text-xl font-bold text-neutral-800">KES {cat.value.toLocaleString()}</p>
             </div>
           ))}
           {expenseByCategory.length === 0 && (
             <div className="md:col-span-4 bg-neutral-100/50 border-2 border-dashed border-neutral-200 p-8 rounded-3xl text-center text-neutral-400 text-xs font-bold uppercase tracking-widest">
