        <div className="bg-white rounded-[3rem] border border-neutral-200 shadow-sm overflow-hidden">
          <div className="p-8 border-b border-neutral-100 flex justify-between items-center bg-neutral-50/50">
             <h3 className="font-bold text-lg text-neutral-800">Transaction Ledger</h3>
             <div className="flex gap-4">
                <div className="relative">
                  <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-neutral-400" />
