                </div>
             </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-neutral-50/80 border-b">
                <tr>
                  <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Post Date</th>
                  <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Classification</th>
                  <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Narration</th>
                  <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest text-right">Debit (KES)</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-neutral-50">
                {expenses.length === 0 && (
                  <tr><td colSpan={4} className="p-32 text-center text-neutral-300 italic text-sm">No expenses recorded for current cycle.</td></tr>
                )}
                {expenses.map(e => (
                  <tr key={e.id} className="hover:bg-neutral-50/80 transition-colors group">
                    <td className="px-10 py-7 text-xs font-bold text-neutral-500">{new Date(e.date).toLocaleDateString()}</td>
                    <td className="px-10 py-7">
                      <span className="bg-white text-neutral-600 px-3 py-1.5 rounded-xl text-[9px] font-black uppercase border border-neutral-200 shadow-sm">{e.category}</span>
                    </td>
                    <td className="px-10 py-7 text-sm font-bold text-neutral-800">{e.description}</td>
                    <td className="px-10 py-7 text-right font-black text-red-500 text-base">-{e.amount.toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    );
  }

  if (view === 'reports') {
    return (
      <div className="space-y-10 animate-fadeIn">
