};

const LogPaymentModal: React.FC<{ tenants: Tenant[], onClose: () => void, onSubmit: (p: PaymentRecord) => void }> = ({ tenants, onClose, onSubmit }) => {
  const [formData, setFormData] = useState({
    tenantId: '',
    amount: '',
    type: 'RENT' as PaymentRecord['type'],
    reference: '',
    method: 'M-Pesa'
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.tenantId) return;

    onSubmit({
      id: `pay-${Date.now()}`,
      tenantId: formData.tenantId,
      amount: Number(formData.amount),
      date: new Date().toISOString(),
      type: formData.type,
      reference: formData.reference || `STAFF-${Math.random().toString(36).substring(7).toUpperCase()}`,
      method: formData.method
    });
