};

const HouseDetailModal: React.FC<{ house: House, onClose: () => void, currentTenant?: Tenant, onUpdateStatus: (s: HouseStatus, r?: Repair) => void, onViewTenant?: (t: Tenant) => void }> = ({ house, onClose, currentTenant, onUpdateStatus, onViewTenant }) => {
  const [pendingStatus, setPendingStatus] = useState<HouseStatus | null>(null);
  const [showRepairForm, setShowRepairForm] = useState(false);
  const [repairData, setRepairData] = useState({ description: '', cost: '', category: 'General' });
  const [activeViewTab, setActiveViewTab] = useState<'maintenance' | 'utility'>('maintenance');

  const handleStatusCommit = () => {
    if (!pendingStatus) return;
    if (pendingStatus === HouseStatus.UNDER_REPAIR) {
      setShowRepairForm(true);
    } else {
      onUpdateStatus(pendingStatus);
      setPendingStatus(null);
    }
  };

  const handleRepairSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const repair: Repair = {
      id: `r-${Date.now()}`,
      date: new Date().toISOString().split('T')[0],
      description: repairData.description,
      cost: Number(repairData.cost),
      category: repairData.category
    };
    onUpdateStatus(HouseStatus.UNDER_REPAIR, repair);
    setShowRepairForm(false);
    setPendingStatus(null);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-neutral-900/90 backdrop-blur-sm animate-fadeIn">
      <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-slideUp border border-neutral-200 flex flex-col max-h-[90vh]">
        <div className="bg-neutral-900 p-10 text-white flex justify-between items-center relative overflow-hidden shrink-0">
          <div className="absolute top-0 right-0 p-8 opacity-10"><Home size={100}/></div>
          <div className="relative z-10">
             <h3 className="text-3xl font-royal font-black tracking-tight">Unit {house.houseNumber}</h3>
             <p className="text-neutral-400 text-xs uppercase font-black tracking-widest mt-1">{house.type} Profile</p>
          </div>
          <button type="button" onClick={onClose} className="relative z-30 p-4 bg-white/10 hover:bg-white/20 rounded-2xl transition-all shadow-lg border border-white/10">
            <X size={24} />
          </button>
        </div>

        <div className="p-10 space-y-8 overflow-y-auto scrollbar-hide">
          {!showRepairForm ? (
            <>
              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-1">
                  <p className="text-[10px] font-black text-neutral-400 uppercase tracking-widest">Current Status</p>
                  <StatusBadge status={house.status} />
                </div>
                <div className="space-y-1">
                  <p className="text-[10px] font-black text-neutral-400 uppercase tracking-widest">Lifetime Earnings</p>
                  <p className="text-xl font-bold text-neutral-800">KES {house.totalEarnings.toLocaleString()}</p>
                </div>
              </div>

              <div className="space-y-4">
                <p className="text-[10px] font-black text-neutral-400 uppercase tracking-widest flex items-center gap-2"><RefreshCw size={14}/> Modify Occupancy Status</p>
                <div className="flex gap-2">
                  <UnitStatusBtn 
                    active={(pendingStatus || house.status) === HouseStatus.RENTED} 
                    onClick={() => setPendingStatus(HouseStatus.RENTED)} 
                    color="green" 
                    label="Rented" 
                    icon={<CheckCircle2 size={18}/>} 
                  />
                  <UnitStatusBtn 
                    active={(pendingStatus || house.status) === HouseStatus.VACANT} 
                    onClick={() => setPendingStatus(HouseStatus.VACANT)} 
                    color="amber" 
                    label="Vacant" 
                    icon={<CircleDashed size={18}/>} 
                  />
                  <UnitStatusBtn 
                    active={(pendingStatus || house.status) === HouseStatus.UNDER_REPAIR} 
                    onClick={() => setPendingStatus(HouseStatus.UNDER_REPAIR)} 
                    color="red" 
                    label="Repair" 
                    icon={<Hammer size={18}/>} 
                  />
                </div>

                {pendingStatus && pendingStatus !== house.status && (
                  <div className="animate-slideUp bg-royal-500 p-1.5 rounded-2xl flex items-center justify-between pl-6 shadow-xl shadow-royal-500/20">
                    <span className="text-white text-[10px] font-black uppercase tracking-widest">Pending: {pendingStatus.replace('_', ' ')}</span>
                    <button 
                      type="button"
                      onClick={handleStatusCommit}
                      className="bg-white text-royal-500 px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-royal-50 active:scale-95 transition-all shadow-lg"
                    >
                      Confirm Change
                    </button>
                  </div>
                )}
              </div>

              {currentTenant ? (
                <div className="bg-royal-50 p-6 rounded-2xl border border-royal-100">
                  <p className="text-[10px] font-black text-royal-500 uppercase tracking-widest mb-2">Current Resident</p>
                  <div className="flex justify-between items-center">
                    <div>
                      <p className="font-bold text-neutral-900">{currentTenant.name}</p>
                      <p className="text-xs text-neutral-500">{currentTenant.phoneNumber}</p>
                    </div>
                    <div className="flex items-center gap-3">
                       <BillStatusBadge status={currentTenant.bills.status} />
                       <button 
                        type="button"
                        onClick={() => onViewTenant?.(currentTenant)}
                        className="p-2.5 bg-white text-royal-500 rounded-xl hover:bg-royal-500 hover:text-white transition-all border border-royal-100 shadow-sm active:scale-90"
                        title="View Profile Intelligence"
                      >
                        <User size={16} />
                      </button>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="bg-amber-50 p-6 rounded-2xl border border-amber-100 flex items-center gap-3">
                  <AlertTriangle className="text-amber-500" size={20} />
                  <p className="text-xs font-bold text-amber-700 uppercase">Unit currently unoccupied</p>
                </div>
              )}

              <div className="space-y-6">
                <div className="flex bg-neutral-100 p-1 rounded-xl w-fit">
                   <button 
                    type="button"
                    onClick={() => setActiveViewTab('maintenance')}
                    className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${activeViewTab === 'maintenance' ? 'bg-white text-royal-500 shadow-sm' : 'text-neutral-400 hover:text-neutral-600'}`}
                   >
                     Maintenance
                   </button>
                   <button 
                    type="button"
                    onClick={() => setActiveViewTab('utility')}
                    disabled={!currentTenant}
                    className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${activeViewTab === 'utility' ? 'bg-white text-royal-500 shadow-sm' : 'text-neutral-400 hover:text-neutral-600'} disabled:opacity-30`}
                   >
                     Utility Audit
                   </button>
                </div>

                {activeViewTab === 'maintenance' && (
                  <div className="space-y-2 animate-fadeIn">
                    {house.repairs.length > 0 ? (
                      house.repairs.map(r => (
                        <div key={r.id} className="flex justify-between items-center p-4 bg-neutral-50 rounded-xl border border-neutral-100">
                          <div>
                            <p className="text-sm font-bold text-neutral-800">{r.description}</p>
                            <p className="text-[10px] text-neutral-400 font-medium">{r.date} • {r.category}</p>
                          </div>
                          <p className="text-sm font-black text-neutral-900">KES {r.cost.toLocaleString()}</p>
                        </div>
                      ))
                    ) : (
                      <p className="text-xs text-neutral-400 italic">No maintenance records for this unit.</p>
                    )}
