                            <div>
                               <p className="text-xs font-bold text-neutral-800">{mr.date}</p>
                               <p className="text-[9px] font-black text-neutral-400 uppercase tracking-widest">Reading: {mr.reading} • Δ {mr.unitsConsumed} units</p>
                            </div>
                          </div>
                          <div className="text-right">
                             <p className="text-sm font-black text-neutral-900">KES {mr.cost.toLocaleString()}</p>
                             <p className="text-[8px] font-black text-green-600 uppercase">Archived</p>
                          </div>
                        </div>
                      ))
