      <div className={`flex items-center gap-1 text-[10px] font-black px-3 py-1.5 rounded-xl border ${trend === 'up' ? 'bg-green-50 text-green-700 border-green-100' : trend === 'down' ? 'bg-red-50 text-red-700 border-red-100' : 'bg-neutral-50 text-neutral-600 border-neutral-200'}`}>
         {trend === 'up' ? <TrendingUp size={12}/> : trend === 'down' ? <TrendingDown size={12}/> : null}
         {change}
      </div>
    </div>
    <div className="text-[11px] text-neutral-400 font-black uppercase tracking-[0.2em] mb-2">{title}</div>
    <div className="text-3xl font-black text-neutral-900 tracking-tight">{value}</div>
  </div>
);

const ReportActionCard: React.FC<{ title: string, desc: string, icon: React.ReactNode, onClick: () => void, accent: 'royal' | 'amber' | 'red' }> = ({ title, desc, icon, onClick, accent }) => {
