const AddExpenseModal: React.FC<{ onAdd: (e: Expense) => void, onClose: () => void }> = ({ onAdd, onClose }) => {
  const [data, setData] = useState({ category: 'MAINTENANCE', amount: '', description: '' });
  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAdd({
      id: `exp-${Date.now()}`,
      date: new Date().toISOString(),
      category: data.category as any,
      amount: Number(data.amount),
      description: data.description
    });
    onClose();
  };
  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-neutral-900/95 backdrop-blur-md animate-fadeIn">
      <div className="bg-white w-full max-w-xl rounded-[4rem] shadow-2xl overflow-hidden animate-slideUp">
        <div className="bg-royal-900 p-12 text-white flex justify-between items-center relative overflow-hidden">
           <div className="absolute top-0 right-0 p-10 opacity-5 text-white"><Briefcase size={120}/></div>
           <div className="relative z-10">
              <h3 className="text-3xl font-royal font-black tracking-tight">Record Expense</h3>
              <p className="text-royal-400 text-[10px] font-black uppercase tracking-[0.3em] mt-1">Operational Outflow Audit</p>
           </div>
           <button onClick={onClose} className="p-4 bg-white/5 hover:bg-white/10 rounded-2xl transition-all shadow-lg"><X size={28}/></button>
        </div>
        <form onSubmit={handleSubmit} className="p-12 space-y-8">
           <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-neutral-500 tracking-widest pl-1">Expense Classification</label>
              <select className="w-full p-5 bg-neutral-50 border-2 border-neutral-100 rounded-3xl outline-none focus:border-royal-500 font-black text-lg transition-all appearance-none" value={data.category} onChange={e => setData({...data, category: e.target.value})}>
                 <option value="MAINTENANCE">Maintenance & Repairs</option>
                 <option value="UTILITIES">Utility Provisions</option>
                 <option value="TAX">Statutory Taxes</option>
                 <option value="LEGAL">Legal & Compliance</option>
                 <option value="SALARY">Staff Salaries</option>
                 <option value="OTHER">Sundry / Miscellaneous</option>
              </select>
           </div>
           <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-neutral-500 tracking-widest pl-1">Amount (KES)</label>
              <input type="number" required className="w-full p-5 bg-neutral-50 border-2 border-neutral-100 rounded-3xl outline-none focus:border-royal-500 font-black text-2xl transition-all" value={data.amount} onChange={e => setData({...data, amount: e.target.value})} />
           </div>
           <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-neutral-500 tracking-widest pl-1">Narration</label>
              <input type="text" required placeholder="Describe the transaction..." className="w-full p-5 bg-neutral-50 border-2 border-neutral-100 rounded-3xl outline-none focus:border-royal-500 font-bold transition-all" value={data.description} onChange={e => setData({...data, description: e.target.value})} />
           </div>
           <button type="submit" className="w-full bg-royal-500 text-white py-6 rounded-[2.5rem] font-black text-sm uppercase tracking-[0.3em] hover:bg-royal-600 shadow-2xl shadow-royal-500/20 active:scale-95 transition-all">Execute Transaction</button>
        </form>
      </div>
    </div>
  );
};

const ReportPreviewModal: React.FC<{ type: string, data: any, onClose: () => void }> = ({ type, data, onClose }) => {
  const printRef = useRef<HTMLDivElement>(null);
  const handlePrint = () => {
    const printContent = printRef.current?.innerHTML;
    const printWindow = window.open('', '', 'height=1000,width=800');
    if (printWindow) {
      printWindow.document.write(`
        <html>
          <head>
            <title>Royal Flats - Official Performance Record</title>
            <script src="https://cdn.tailwindcss.com"></script>
            <style>
              @media print { .no-print { display: none; } body { padding: 0; margin: 0; background: white; } }
              body { padding: 40px; font-family: 'Times New Roman', serif; background: #f1f5f9; }
              .page { background: white; padding: 60px; margin: auto; max-width: 800px; min-height: 1100px; box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); }
            </style>
          </head>
          <body>
            <div class="page">${printContent}</div>
            <script>window.print(); setTimeout(() => window.close(), 500);</script>
          </body>
        </html>
      `);
      printWindow.document.close();
    }
  };

  return (
    <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-neutral-900/95 backdrop-blur-xl animate-fadeIn">
